// autoforge CLI — tests for the --auto loop mode path
import { describe, it, beforeEach, afterEach } from 'node:test';
import assert from 'node:assert';
import fs from 'node:fs/promises';
import os from 'node:os';
import path from 'node:path';
import { autoforge } from '../src/cli/commands/autoforge.js';
import {
  AutoforgeLoopState,
  type AutoforgeLoopContext,
} from '../src/core/autoforge-loop.js';

// Reset process.exitCode between tests so mutations don't leak
let _savedExitCode: number | undefined;
const tempDirs: string[] = [];
const originalCwd = process.cwd();
beforeEach(() => { _savedExitCode = process.exitCode as number | undefined; process.exitCode = undefined; });
afterEach(async () => {
  process.exitCode = _savedExitCode;
  process.chdir(originalCwd);
  while (tempDirs.length > 0) {
    const dir = tempDirs.pop();
    if (dir) {
      await fs.rm(dir, { recursive: true, force: true });
    }
  }
});

async function makeWorkspace(): Promise<string> {
  const dir = await fs.mkdtemp(path.join(os.tmpdir(), 'df-autoforge-cli-'));
  tempDirs.push(dir);
  await fs.mkdir(path.join(dir, '.danteforge'), { recursive: true });
  return dir;
}

function makeLoopCtx(overrides: Partial<AutoforgeLoopContext> = {}): AutoforgeLoopContext {
  return {
    goal: 'test-goal',
    cwd: process.cwd(),
    state: { project: 'test', workflowStage: 'initialized', currentPhase: 1, tasks: {}, lastHandoff: 'none', profile: 'balanced', auditLog: [] },
    loopState: AutoforgeLoopState.COMPLETE,
    cycleCount: 1,
    startedAt: new Date().toISOString(),
    retryCounters: {},
    blockedArtifacts: [],
    lastGuidance: null,
    isWebProject: false,
    force: false,
    maxRetries: 3,
    ...overrides,
  };
}

describe('autoforge CLI — --auto loop mode', () => {
  it('calls _runLoop when auto=true', async () => {
    let called = false;
    await autoforge('test-goal', {
      auto: true,
      _runLoop: async (ctx) => { called = true; return makeLoopCtx({ ...ctx, loopState: AutoforgeLoopState.COMPLETE }); },
    });
    assert.ok(called, '_runLoop should be invoked when auto=true');
  });

  it('does NOT call _runLoop when auto is absent (uses dry-run to exit early)', async () => {
    let called = false;
    await autoforge(undefined, {
      dryRun: true,
      _runLoop: async (ctx) => { called = true; return ctx; },
    });
    assert.strictEqual(called, false, '_runLoop should not be called without --auto flag');
  });

  it('sets exitCode=1 when loop returns BLOCKED state', async () => {
    await autoforge(undefined, {
      auto: true,
      _runLoop: async (ctx) => makeLoopCtx({
        ...ctx,
        loopState: AutoforgeLoopState.BLOCKED,
        blockedArtifacts: ['src/core/state.ts'],
      }),
    });
    assert.strictEqual(process.exitCode, 1, 'BLOCKED loop result should set exitCode=1');
  });

  it('passes the goal string into loop context', async () => {
    let receivedGoal = '';
    await autoforge('my-specific-goal', {
      auto: true,
      _runLoop: async (ctx) => { receivedGoal = ctx.goal; return makeLoopCtx(ctx); },
    });
    assert.strictEqual(receivedGoal, 'my-specific-goal', 'goal should be passed to loop context');
  });

  it('passes force flag into loop context', async () => {
    let receivedForce = false;
    await autoforge(undefined, {
      auto: true,
      force: true,
      _runLoop: async (ctx) => { receivedForce = ctx.force; return makeLoopCtx(ctx); },
    });
    assert.ok(receivedForce, 'force flag should be passed to loop context');
  });

  it('delegates score-only mode to the injected score runner', async () => {
    let called = false;
    await autoforge(undefined, {
      scoreOnly: true,
      _runScoreOnlyMode: async () => { called = true; },
    });
    assert.ok(called, 'score-only mode should invoke the injected score runner');
  });

  it('uses injected analysis + planner in prompt mode without executing the plan', async () => {
    let executeCalled = false;
    let analyzed = false;
    let planned = false;

    await autoforge('ship it', {
      prompt: true,
      _analyzeProjectState: async () => {
        analyzed = true;
        return {
          state: makeLoopCtx().state,
          hasDesignOp: false,
          hasUI: false,
          memoryEntryCount: 0,
          lastMemoryAge: null,
          failedAttempts: 0,
          designViolationCount: 0,
        };
      },
      _planAutoForge: (input, maxWaves, goal) => {
        planned = true;
        assert.equal(goal, 'ship it');
        return {
          scenario: 'cold-start',
          reasoning: 'test',
          steps: [{ command: 'review', reason: 'scan' }],
          maxWaves,
          goal,
        };
      },
      _executeAutoForgePlan: async () => {
        executeCalled = true;
        return { completed: [], failed: [], paused: false };
      },
    });

    assert.ok(analyzed, 'prompt mode should analyze project state');
    assert.ok(planned, 'prompt mode should build a plan');
    assert.equal(executeCalled, false, 'prompt mode should not execute the plan');
  });

  it('uses injected displayPlan in dry-run mode', async () => {
    let displayed = false;

    await autoforge(undefined, {
      dryRun: true,
      _analyzeProjectState: async () => ({
        state: makeLoopCtx().state,
        hasDesignOp: false,
        hasUI: false,
        memoryEntryCount: 0,
        lastMemoryAge: null,
        failedAttempts: 0,
        designViolationCount: 0,
      }),
      _planAutoForge: () => ({
        scenario: 'cold-start',
        reasoning: 'test',
        steps: [{ command: 'review', reason: 'scan' }],
        maxWaves: 3,
      }),
      _displayPlan: () => { displayed = true; },
    });

    assert.ok(displayed, 'dry-run mode should display the generated plan');
  });

  it('uses injected executor in standard execution mode and marks failures via exitCode', async () => {
    await autoforge(undefined, {
      _analyzeProjectState: async () => ({
        state: makeLoopCtx().state,
        hasDesignOp: false,
        hasUI: false,
        memoryEntryCount: 0,
        lastMemoryAge: null,
        failedAttempts: 0,
        designViolationCount: 0,
      }),
      _planAutoForge: () => ({
        scenario: 'mid-project',
        reasoning: 'test',
        steps: [{ command: 'forge', reason: 'build' }],
        maxWaves: 3,
      }),
      _executeAutoForgePlan: async () => ({
        completed: [],
        failed: ['forge'],
        paused: false,
      }),
      _loadLatestVerdict: async () => null,
    });

    assert.strictEqual(process.exitCode, 1, 'failed execution should set exitCode=1');
  });

  it('writes AUTOFORGE_GUIDANCE.md in a real score-only workspace', async () => {
    const cwd = await makeWorkspace();
    process.chdir(cwd);

    await fs.writeFile(path.join(cwd, '.danteforge', 'STATE.yaml'), [
      'project: autoforge-cli-real',
      `created: ${new Date().toISOString()}`,
      'workflowStage: initialized',
      'currentPhase: 0',
      'lastHandoff: none',
      'profile: balanced',
      'tasks: {}',
      'gateResults: {}',
      'auditLog: []',
    ].join('\n'));

    await autoforge(undefined, { scoreOnly: true });

    const guidance = await fs.readFile(path.join(cwd, '.danteforge', 'AUTOFORGE_GUIDANCE.md'), 'utf8');
    assert.match(guidance, /# Autoforge Guidance/);
    assert.match(guidance, /Overall Completion:/);
  });

  it('loads and reports reflection data when the verdict is available', async () => {
    let verdictLoaded = false;

    await autoforge(undefined, {
      _analyzeProjectState: async () => ({
        state: makeLoopCtx().state,
        hasDesignOp: false,
        hasUI: false,
        memoryEntryCount: 0,
        lastMemoryAge: null,
        failedAttempts: 0,
        designViolationCount: 0,
      }),
      _planAutoForge: () => ({
        scenario: 'mid-project',
        reasoning: 'test',
        steps: [{ command: 'forge', reason: 'build' }],
        maxWaves: 3,
      }),
      _executeAutoForgePlan: async () => ({
        completed: ['forge'],
        failed: [],
        paused: false,
      }),
      _loadLatestVerdict: async () => {
        verdictLoaded = true;
        return {
          confidence: 0.92,
          status: 'ready',
          stuck: false,
          remainingWork: ['final polish'],
        };
      },
    });

    assert.ok(verdictLoaded, 'execution mode should load the latest reflection verdict');
    assert.strictEqual(process.exitCode, undefined);
  });
});

// autoforge — deterministic state machine that auto-orchestrates the DanteForge pipeline
import fs from 'fs/promises';
import path from 'path';
import { logger } from '../../core/logger.js';
import { loadState, saveState } from '../../core/state.js';
import {
  analyzeProjectState,
  planAutoForge,
  executeAutoForgePlan,
  displayPlan,
} from '../../core/autoforge.js';
import {
  runAutoforgeLoop,
  AutoforgeLoopState,
  type AutoforgeLoopContext,
  type AutoforgeLoopDeps,
} from '../../core/autoforge-loop.js';
import {
  scoreAllArtifacts,
  persistScoreResult,
  type ScoreResult,
  type ScoredArtifact,
} from '../../core/pdse.js';
import {
  computeCompletionTracker,
  detectProjectType,
} from '../../core/completion-tracker.js';
import { SCORE_THRESHOLDS, ARTIFACT_COMMAND_MAP } from '../../core/pdse-config.js';
import { loadLatestVerdict } from '../../core/reflection-engine.js';

export async function autoforge(goal?: string, options: {
  dryRun?: boolean;
  maxWaves?: number;
  light?: boolean;
  prompt?: boolean;
  scoreOnly?: boolean;
  auto?: boolean;
  force?: boolean;
  profile?: string;
  parallel?: boolean;
  worktree?: boolean;
  /** Injection seam: replaces runAutoforgeLoop in --auto mode (for testing) */
  _runLoop?: (ctx: AutoforgeLoopContext, deps?: Partial<AutoforgeLoopDeps>) => Promise<AutoforgeLoopContext>;
  /** Injection seam: replaces score-only mode runner (for testing) */
  _runScoreOnlyMode?: () => Promise<void>;
  /** Injection seam: replaces analyzeProjectState (for testing) */
  _analyzeProjectState?: typeof analyzeProjectState;
  /** Injection seam: replaces planAutoForge (for testing) */
  _planAutoForge?: typeof planAutoForge;
  /** Injection seam: replaces displayPlan (for testing) */
  _displayPlan?: typeof displayPlan;
  /** Injection seam: replaces executeAutoForgePlan (for testing) */
  _executeAutoForgePlan?: typeof executeAutoForgePlan;
  /** Injection seam: replaces loadLatestVerdict (for testing) */
  _loadLatestVerdict?: typeof loadLatestVerdict;
} = {}): Promise<void> {
  const maxWaves = options.maxWaves ?? 3;
  const runScoreOnly = options._runScoreOnlyMode ?? runScoreOnlyMode;
  const analyze = options._analyzeProjectState ?? analyzeProjectState;
  const planPipeline = options._planAutoForge ?? planAutoForge;
  const renderPlan = options._displayPlan ?? displayPlan;
  const executePlan = options._executeAutoForgePlan ?? executeAutoForgePlan;
  const loadVerdict = options._loadLatestVerdict ?? loadLatestVerdict;

  logger.success('DanteForge AutoForge - Agentic Pipeline Orchestrator');
  logger.info('');

  // --score-only mode: score existing artifacts and write guidance
  if (options.scoreOnly) {
    await runScoreOnly();
    return;
  }

  // --auto mode: run continuous loop (score → plan → execute → repeat) until 95% or BLOCKED
  if (options.auto) {
    const { spawnSync } = await import('node:child_process');
    const _runLoop = options._runLoop ?? runAutoforgeLoop;
    const state = await loadState({ cwd: process.cwd() });

    const ctx: AutoforgeLoopContext = {
      goal: goal ?? state.project ?? 'autoforge',
      cwd: process.cwd(),
      state,
      loopState: AutoforgeLoopState.IDLE,
      cycleCount: 0,
      startedAt: new Date().toISOString(),
      retryCounters: {},
      blockedArtifacts: [],
      lastGuidance: null,
      isWebProject: false,
      force: options.force ?? false,
      maxRetries: 3,
      dryRun: options.dryRun ?? false,
    };

    const executeCmd = async (command: string, cwd: string): Promise<{ success: boolean }> => {
      const [cmd, ...rest] = command.trim().split(' ');
      const result = spawnSync(process.execPath, [process.argv[1], cmd, ...rest], {
        cwd, stdio: 'inherit', encoding: 'utf8',
      });
      return { success: result.status === 0 };
    };

    const loopResult = await _runLoop(ctx, { _executeCommand: executeCmd });
    if (loopResult.loopState === AutoforgeLoopState.BLOCKED) {
      logger.error(`[Autoforge] Loop blocked on: ${loopResult.blockedArtifacts.join(', ')}`);
      process.exitCode = 1;
    }
    return;
  }

  // Analyze current project state
  logger.info('Analyzing project state...');
  const input = await analyze();

  // Generate the plan
  const plan = planPipeline(input, maxWaves, goal);

  // --prompt mode: generate copy-paste prompt
  if (options.prompt) {
    const prompt = generateAutoForgePrompt(plan, input);
    logger.success('=== COPY-PASTE PROMPT (start) ===');
    process.stdout.write('\n' + prompt + '\n\n');
    logger.success('=== COPY-PASTE PROMPT (end) ===');
    logger.info('');
    logger.info('Paste this into your LLM interface to get guidance on executing these steps.');
    return;
  }

  // --dry-run mode: display plan without executing
  if (options.dryRun) {
    renderPlan(plan);
    logger.info('[AutoForge] Dry run complete — no commands were executed.');
    return;
  }

  // Execute the plan
  const result = await executePlan(plan, {
    dryRun: false,
    light: options.light,
    profile: options.profile,
    parallel: options.parallel,
    worktree: options.worktree,
  });

  // Report results
  logger.info('');
  logger.info('='.repeat(60));
  if (result.failed.length > 0) {
    logger.error('  AUTOFORGE COMPLETED WITH FAILURES');
  } else if (result.paused) {
    logger.info('  AUTOFORGE PAUSED AT CHECKPOINT');
  } else {
    logger.success('  AUTOFORGE COMPLETE');
  }
  logger.info('='.repeat(60));
  logger.info('');

  if (result.completed.length > 0) {
    logger.success(`Completed: ${result.completed.join(' -> ')}`);
  }
  if (result.failed.length > 0) {
    logger.error(`Failed: ${result.failed.join(', ')}`);
    logger.info('Run `danteforge doctor` to diagnose, then `danteforge autoforge` to retry.');
    process.exitCode = 1;
  }
  if (result.paused) {
    logger.info(`Paused after ${maxWaves} waves. Run \`danteforge autoforge\` again to continue.`);
  }

  // Show reflection score if available
  try {
    const verdict = await loadVerdict();
    if (verdict) {
      const score = Math.round(verdict.confidence * 100);
      logger.info('');
      logger.info(`Reflection: ${score}/100 (${verdict.status})${verdict.stuck ? ' [STUCK]' : ''}`);
      if (verdict.remainingWork.length > 0) {
        logger.warn(`Remaining: ${verdict.remainingWork.slice(0, 3).join(', ')}`);
      }
    }
  } catch {
    // Reflection not available — no problem
  }
}

// ── Score-only mode ─────────────────────────────────────────────────────────

async function runScoreOnlyMode(): Promise<void> {
  const cwd = process.cwd();
  logger.info('Scoring existing artifacts...');

  const state = await loadState();
  state.projectType = await detectProjectType(cwd);

  const scores = await scoreAllArtifacts(cwd, state);

  // Persist all scores
  for (const result of Object.values(scores)) {
    await persistScoreResult(result, cwd);
  }

  // Compute completion tracker
  const tracker = computeCompletionTracker(state, scores);
  state.completionTracker = tracker;
  state.auditLog.push(
    `${new Date().toISOString()} | pdse-score | score-only pass — overall: ${tracker.overall}%`,
  );
  await saveState(state);

  // Write AUTOFORGE_GUIDANCE.md
  const guidance = buildGuidanceMarkdown(scores, tracker);
  const guidancePath = path.join(cwd, '.danteforge', 'AUTOFORGE_GUIDANCE.md');
  await fs.mkdir(path.join(cwd, '.danteforge'), { recursive: true });
  await fs.writeFile(guidancePath, guidance);

  // Print score table
  logger.info('');
  logger.success('DanteForge v0.9.2 — Score-Only Pass');
  logger.info('━'.repeat(40));

  const artifacts: ScoredArtifact[] = ['CONSTITUTION', 'SPEC', 'CLARIFY', 'PLAN', 'TASKS'];
  for (const name of artifacts) {
    const result = scores[name];
    const icon = result.score >= SCORE_THRESHOLDS.EXCELLENT ? '✓ EXCELLENT'
      : result.score >= SCORE_THRESHOLDS.ACCEPTABLE ? '✓ ACCEPTABLE'
      : result.score >= SCORE_THRESHOLDS.NEEDS_WORK ? '⚠ NEEDS WORK'
      : '✗ BLOCKED';
    const padded = `${name}.md`.padEnd(22);
    logger.info(`${padded}${String(result.score).padStart(3)}  ${icon}`);
  }

  logger.info('');
  logger.info(`Overall completion:  ${tracker.overall}%`);

  // Reflection score (from last reflection verdict)
  const verdict = await loadLatestVerdict(cwd);
  if (verdict) {
    const reflectionScore = Math.round(verdict.confidence * 100);
    const reflectionIcon = reflectionScore >= 80 ? '✓' : reflectionScore >= 50 ? '⚠' : '✗';
    logger.info(`Reflection score:    ${reflectionScore}  ${reflectionIcon} (${verdict.status})`);
  }

  // Find bottleneck
  const bottleneck = findBottleneck(scores);
  if (bottleneck) {
    logger.info(`Current bottleneck:  ${bottleneck.artifact}.md (${bottleneck.worstDimension}: ${bottleneck.worstScore}/${bottleneck.maxScore})`);
  }

  // Recommended next action
  const recommendation = getRecommendation(scores);
  if (recommendation) {
    logger.info('');
    logger.info('Recommended next action:');
    logger.info(`  danteforge ${recommendation.command}`);
    logger.info(`  Reason: ${recommendation.reason}`);
  }

  logger.info('');
  logger.info(`Guidance written to: ${guidancePath}`);
}

// ── Guidance file generation ────────────────────────────────────────────────

function buildGuidanceMarkdown(
  scores: Record<ScoredArtifact, ScoreResult>,
  tracker: ReturnType<typeof computeCompletionTracker>,
): string {
  const timestamp = new Date().toISOString();
  const artifacts: ScoredArtifact[] = ['CONSTITUTION', 'SPEC', 'CLARIFY', 'PLAN', 'TASKS'];

  const bottleneck = findBottleneck(scores);
  const recommendation = getRecommendation(scores);
  const blockingIssues = getBlockingIssues(scores);
  const autoAdvance = artifacts.every(a => scores[a].score >= SCORE_THRESHOLDS.NEEDS_WORK);

  const lines: string[] = [
    '# Autoforge Guidance',
    `> Generated: ${timestamp}`,
    '',
    `## Overall Completion: ${tracker.overall}%`,
    '',
    '| Phase | Score | Complete |',
    '|---|---|---|',
    `| Planning | ${tracker.phases.planning.score} | ${tracker.phases.planning.complete ? 'Yes' : 'No'} |`,
    `| Execution | ${tracker.phases.execution.score} | ${tracker.phases.execution.complete ? 'Yes' : 'No'} |`,
    `| Verification | ${tracker.phases.verification.score} | ${tracker.phases.verification.complete ? 'Yes' : 'No'} |`,
    `| Synthesis | ${tracker.phases.synthesis.score} | ${tracker.phases.synthesis.complete ? 'Yes' : 'No'} |`,
    '',
    '## Current Bottleneck',
    bottleneck
      ? `${bottleneck.artifact}.md — ${bottleneck.worstDimension}: ${bottleneck.worstScore}/${bottleneck.maxScore}`
      : '_None_',
    '',
    '## Blocking Issues',
    blockingIssues.length > 0
      ? blockingIssues.map(i => `- **${i.artifact}.md** (${i.score}): ${i.message}`).join('\n')
      : '_None_',
    '',
    '## Artifact Scores',
    '| Artifact | Score | Decision |',
    '|---|---|---|',
    ...artifacts.map(a =>
      `| ${a}.md | ${scores[a].score} | ${scores[a].autoforgeDecision} |`,
    ),
    '',
    '## Recommended Next Action',
    '```',
    recommendation ? `danteforge ${recommendation.command}` : '# No action required',
    '```',
    recommendation ? `**Reason:** ${recommendation.reason}` : '',
    '',
    '## Auto-Advance Eligibility',
    autoAdvance
      ? 'YES — all scores >= 50'
      : `NO — ${artifacts.filter(a => scores[a].score < SCORE_THRESHOLDS.NEEDS_WORK).map(a => `${a}.md`).join(', ')} below threshold`,
    '',
    '## Estimated Steps to Completion',
    `${tracker.projectedCompletion}`,
  ];

  // Append reflection score if available (async not possible here, so read state)
  if (typeof globalThis !== 'undefined') {
    lines.push('', '## Reflection Score');
    lines.push('_Run `danteforge autoforge --score-only` to see latest reflection verdict._');
  }

  return lines.join('\n') + '\n';
}

// ── Helpers ─────────────────────────────────────────────────────────────────

interface Bottleneck {
  artifact: ScoredArtifact;
  worstDimension: string;
  worstScore: number;
  maxScore: number;
}

function findBottleneck(scores: Record<ScoredArtifact, ScoreResult>): Bottleneck | null {
  let worst: Bottleneck | null = null;
  const artifacts: ScoredArtifact[] = ['CONSTITUTION', 'SPEC', 'CLARIFY', 'PLAN', 'TASKS'];

  for (const name of artifacts) {
    const result = scores[name];
    if (!worst || result.score < scores[worst.artifact].score) {
      // Find the lowest dimension
      const dims = result.dimensions;
      const dimEntries = Object.entries(dims) as [keyof typeof dims, number][];
      const lowestDim = dimEntries.reduce((a, b) => a[1] <= b[1] ? a : b);
      const maxScore = lowestDim[0] === 'integrationFitness' || lowestDim[0] === 'freshness' ? 10 : 20;
      worst = {
        artifact: name,
        worstDimension: lowestDim[0],
        worstScore: lowestDim[1],
        maxScore,
      };
    }
  }
  return worst;
}

interface Recommendation {
  command: string;
  reason: string;
}

function getRecommendation(scores: Record<ScoredArtifact, ScoreResult>): Recommendation | null {
  const artifacts: ScoredArtifact[] = ['CONSTITUTION', 'SPEC', 'CLARIFY', 'PLAN', 'TASKS'];

  // Find the worst-scoring artifact that has issues
  let worstArtifact: ScoredArtifact | null = null;
  let worstScore = Infinity;

  for (const name of artifacts) {
    if (scores[name].score < worstScore) {
      worstScore = scores[name].score;
      worstArtifact = name;
    }
  }

  if (!worstArtifact || worstScore >= SCORE_THRESHOLDS.EXCELLENT) return null;

  const result = scores[worstArtifact];
  const command = ARTIFACT_COMMAND_MAP[worstArtifact];
  const topIssue = result.issues[0];
  const reason = topIssue
    ? topIssue.message
    : `Score ${result.score} is below ${SCORE_THRESHOLDS.EXCELLENT}`;

  return { command, reason };
}

interface BlockingIssueInfo {
  artifact: ScoredArtifact;
  score: number;
  message: string;
}

function getBlockingIssues(scores: Record<ScoredArtifact, ScoreResult>): BlockingIssueInfo[] {
  const issues: BlockingIssueInfo[] = [];
  const artifacts: ScoredArtifact[] = ['CONSTITUTION', 'SPEC', 'CLARIFY', 'PLAN', 'TASKS'];

  for (const name of artifacts) {
    if (scores[name].autoforgeDecision === 'blocked') {
      issues.push({
        artifact: name,
        score: scores[name].score,
        message: scores[name].issues[0]?.message ?? 'Score below threshold',
      });
    }
  }
  return issues;
}

function generateAutoForgePrompt(
  plan: ReturnType<typeof planAutoForge>,
  input: Awaited<ReturnType<typeof analyzeProjectState>>,
): string {
  const lines: string[] = [
    '# AutoForge Pipeline Plan',
    '',
    ...(plan.goal ? [`**Goal:** ${plan.goal}`, ''] : []),
    `**Scenario:** ${plan.scenario}`,
    `**Current Stage:** ${input.state.workflowStage ?? 'initialized'}`,
    `**Reasoning:** ${plan.reasoning}`,
    '',
    '## Steps to Execute',
    '',
  ];

  for (let i = 0; i < plan.steps.length; i++) {
    const step = plan.steps[i];
    lines.push(`${i + 1}. \`danteforge ${step.command}\` — ${step.reason}`);
  }

  lines.push('', '## Project Context', '');
  lines.push(`- UI Project: ${input.hasUI ? 'Yes' : 'No'}`);
  lines.push(`- Design File: ${input.hasDesignOp ? 'Yes' : 'No'}`);
  lines.push(`- Memory Entries: ${input.memoryEntryCount}`);
  lines.push(`- Design Violations: ${input.designViolationCount}`);
  lines.push(`- Failed Attempts: ${input.failedAttempts}`);

  return lines.join('\n');
}

// Audit logger with log level control
import chalk from 'chalk';

export type LogLevel = 'silent' | 'error' | 'warn' | 'info' | 'verbose';

const LEVEL_ORDER: Record<LogLevel, number> = {
  silent: 0,
  error: 1,
  warn: 2,
  info: 3,
  verbose: 4,
};

let currentLevel: LogLevel = 'info';
let _stderrMode = false;

function shouldLog(level: LogLevel): boolean {
  return LEVEL_ORDER[level] <= LEVEL_ORDER[currentLevel];
}

// When _stderrMode is active, stdout-bound log messages are redirected to stderr
// so that --json callers receive clean JSON on stdout without log noise.
function _log(msg: string): void {
  if (_stderrMode) {
    process.stderr.write(msg + '\n');
  } else {
    process.stdout.write(msg + '\n');
  }
}

export const logger = {
  setLevel(level: LogLevel) { currentLevel = level; },
  getLevel(): LogLevel { return currentLevel; },
  /** Redirect non-error log output to stderr. Use when --json flag is active. */
  setStderr(enabled: boolean) { _stderrMode = enabled; },
  verbose: (msg: string) => { if (shouldLog('verbose')) _log(chalk.gray(`[DBG] ${msg}`)); },
  info: (msg: string) => { if (shouldLog('info')) _log(chalk.blue(`[INFO] ${msg}`)); },
  success: (msg: string) => { if (shouldLog('info')) _log(chalk.green(`[OK] ${msg}`)); },
  warn: (msg: string) => { if (shouldLog('warn')) _log(chalk.yellow(`[WARN] ${msg}`)); },
  error: (msg: string) => { if (shouldLog('error')) console.error(chalk.red(`[ERR] ${msg}`)); },
};

// Core state management — YAML-based project state tracking
import fs from 'fs/promises';
import path from 'path';
import yaml from 'yaml';
import { logger } from './logger.js';
import type { CompletionTracker, ProjectType } from './completion-tracker.js';
import type { SelfEditPolicy } from './safe-self-edit.js';

const STATE_DIR = '.danteforge';
const STATE_FILE = path.join(STATE_DIR, 'STATE.yaml');
const LEGACY_DEFAULT_PROJECT = 'legacy-project';

export type WorkflowStage =
  | 'initialized'
  | 'review'
  | 'constitution'
  | 'specify'
  | 'clarify'
  | 'plan'
  | 'tasks'
  | 'design'
  | 'forge'
  | 'ux-refine'
  | 'verify'
  | 'synthesize';

function resolveStatePaths(cwd = process.cwd()) {
  const stateDir = path.join(cwd, STATE_DIR);
  return {
    stateDir,
    stateFile: path.join(stateDir, 'STATE.yaml'),
  };
}

export interface DanteState {
  project: string;
  constitution?: string;
  lastHandoff: string;
  workflowStage: WorkflowStage;
  currentPhase: number;
  tasks: Record<number, { name: string; files?: string[]; verify?: string }[]>;
  auditLog: string[];
  profile: string;
  lastVerifiedAt?: string;
  // Extended state fields
  tddEnabled?: boolean;
  lightMode?: boolean;
  activeWorktrees?: string[];
  // UX refinement / Figma sync
  uxRefineEnabled?: boolean;
  figmaUrl?: string;
  designTokensPath?: string;
  mcpHost?: string;
  // Design-as-Code pipeline (v0.6.0)
  designEnabled?: boolean;
  designFilePath?: string;
  designPreviewPath?: string;
  designTokensSyncedAt?: string;
  designBackend?: 'figma' | 'openpencil' | 'both';
  designFormatVersion?: string;
  // v0.6.0 — Memory, Workflow Enforcement, AutoForge
  memoryEnabled?: boolean;
  enforcementMode?: 'strict' | 'advisory';
  autoforgeEnabled?: boolean;
  autoforgeFailedAttempts?: number;
  autoforgeLastRunAt?: string;
  // v0.8.0 — PDSE, Completion Tracking, QA, Retro
  projectType?: ProjectType;
  qaHealthScore?: number;
  qaBaseline?: string;
  qaLastRun?: string;
  retroDelta?: number;
  retroLastRun?: string;
  completionTracker?: CompletionTracker;
  // v0.9.0 — Reflection Engine + Premium
  reflectionEnabled?: boolean;
  reflectionAttempts?: number;
  reflectionLastVerdict?: string;
  reflectionScore?: number;
  premiumTier?: 'free' | 'pro' | 'enterprise';
  premiumLicenseKey?: string;
  auditTrailEnabled?: boolean;
  // v0.9.0 — Self-edit policy enforcement
  selfEditPolicy?: SelfEditPolicy;
  lastProtectedEditAt?: string;
  lastProtectedEditDecision?: 'approved' | 'denied';
  // v0.9.0 — Verify receipt spine
  lastVerifyReceiptPath?: string;
  lastVerifySha?: string;
  lastVerifyStatus?: 'pass' | 'warn' | 'fail';
}

export function recordWorkflowStage(
  state: DanteState,
  workflowStage: WorkflowStage,
  timestamp = new Date().toISOString(),
): string {
  state.workflowStage = workflowStage;
  state.lastHandoff = `${workflowStage} -> next (${timestamp})`;
  return timestamp;
}

async function fileExists(filePath: string): Promise<boolean> {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

async function deriveProjectName(existingProject: string | undefined, cwd: string): Promise<string> {
  const cwdName = path.basename(cwd);
  try {
    const pkg = JSON.parse(await fs.readFile(path.join(cwd, 'package.json'), 'utf8')) as { name?: string };
    if (pkg.name && pkg.name.trim().length > 0) {
      if (!existingProject || existingProject === LEGACY_DEFAULT_PROJECT || existingProject === cwdName) {
        return pkg.name.trim();
      }
      return existingProject;
    }
  } catch {
    // Fall back to the workspace folder name.
  }

  if (existingProject && existingProject !== LEGACY_DEFAULT_PROJECT) {
    return existingProject;
  }

  return cwdName;
}

async function inferWorkflowStage(cwd: string, parsed?: Partial<DanteState>): Promise<WorkflowStage> {
  const stateDir = path.join(cwd, STATE_DIR);
  const has = (filename: string) => fileExists(path.join(stateDir, filename));

  if (parsed?.workflowStage) return parsed.workflowStage;
  if (await has('UPR.md')) return 'synthesize';
  if (parsed?.lastVerifiedAt) return 'verify';
  if ((await has('UX_REFINE.md')) || (await has('design-tokens.css'))) return 'ux-refine';
  if (await has('DESIGN.op')) return 'design';
  if (await has('TASKS.md')) return 'tasks';
  if (await has('PLAN.md')) return 'plan';
  if (await has('CLARIFY.md')) return 'clarify';
  if (await has('SPEC.md')) return 'specify';
  if ((await has('CONSTITUTION.md')) || parsed?.constitution) return 'constitution';
  if (await has('CURRENT_STATE.md')) return 'review';
  return 'initialized';
}

export async function loadState(options: { cwd?: string } = {}): Promise<DanteState> {
  const cwd = options.cwd ?? process.cwd();
  const { stateDir, stateFile } = resolveStatePaths(cwd);
  try {
    await fs.mkdir(stateDir, { recursive: true });
    const content = await fs.readFile(stateFile, 'utf8');
    const parsed = yaml.parse(content) as Partial<DanteState>;
    // Validate required fields — fill gaps with defaults
    const project = await deriveProjectName(parsed?.project, cwd);
    const workflowStage = await inferWorkflowStage(cwd, parsed);
    return {
      project,
      lastHandoff: parsed?.lastHandoff ?? 'initialized',
      workflowStage,
      currentPhase: parsed?.currentPhase ?? 0,
      tasks: parsed?.tasks ?? {},
      auditLog: Array.isArray(parsed?.auditLog) ? parsed.auditLog : [],
      profile: parsed?.profile ?? 'balanced',
      constitution: parsed?.constitution,
      lastVerifiedAt: parsed?.lastVerifiedAt,
      tddEnabled: parsed?.tddEnabled,
      lightMode: parsed?.lightMode,
      activeWorktrees: parsed?.activeWorktrees,
      uxRefineEnabled: parsed?.uxRefineEnabled,
      figmaUrl: parsed?.figmaUrl,
      designTokensPath: parsed?.designTokensPath,
      mcpHost: parsed?.mcpHost,
      designEnabled: parsed?.designEnabled,
      designFilePath: parsed?.designFilePath,
      designPreviewPath: parsed?.designPreviewPath,
      designTokensSyncedAt: parsed?.designTokensSyncedAt,
      designBackend: parsed?.designBackend,
      designFormatVersion: parsed?.designFormatVersion,
      memoryEnabled: parsed?.memoryEnabled,
      enforcementMode: parsed?.enforcementMode,
      autoforgeEnabled: parsed?.autoforgeEnabled,
      autoforgeFailedAttempts: parsed?.autoforgeFailedAttempts,
      autoforgeLastRunAt: parsed?.autoforgeLastRunAt,
      // v0.8.0 migration defaults
      projectType: (parsed?.projectType as ProjectType | undefined) ?? 'unknown',
      qaHealthScore: parsed?.qaHealthScore as number | undefined,
      qaBaseline: parsed?.qaBaseline as string | undefined,
      qaLastRun: parsed?.qaLastRun as string | undefined,
      retroDelta: parsed?.retroDelta as number | undefined,
      retroLastRun: parsed?.retroLastRun as string | undefined,
      completionTracker: parsed?.completionTracker as CompletionTracker | undefined,
      // v0.9.0 migration defaults
      reflectionEnabled: parsed?.reflectionEnabled,
      reflectionAttempts: parsed?.reflectionAttempts,
      reflectionLastVerdict: parsed?.reflectionLastVerdict,
      reflectionScore: parsed?.reflectionScore,
      premiumTier: parsed?.premiumTier as 'free' | 'pro' | 'enterprise' | undefined,
      premiumLicenseKey: parsed?.premiumLicenseKey,
      auditTrailEnabled: parsed?.auditTrailEnabled,
      selfEditPolicy: parsed?.selfEditPolicy as SelfEditPolicy | undefined,
      lastProtectedEditAt: parsed?.lastProtectedEditAt,
      lastProtectedEditDecision: parsed?.lastProtectedEditDecision as 'approved' | 'denied' | undefined,
      lastVerifyReceiptPath: parsed?.lastVerifyReceiptPath,
      lastVerifySha: parsed?.lastVerifySha,
      lastVerifyStatus: parsed?.lastVerifyStatus as 'pass' | 'warn' | 'fail' | undefined,
    };
  } catch (err) {
    // Only log if this is NOT a "file not found" — real errors should surface
    if (err instanceof Error && !err.message.includes('ENOENT')) {
      logger.warn(`Failed to load STATE.yaml: ${err.message} — using defaults`);
    }
    const defaultState: DanteState = {
      project: await deriveProjectName(undefined, cwd),
      lastHandoff: 'initialized',
      workflowStage: 'initialized',
      currentPhase: 0,
      tasks: {},
      auditLog: [],
      profile: 'balanced',
      constitution: undefined,
      lastVerifiedAt: undefined,
      tddEnabled: undefined,
      lightMode: undefined,
      activeWorktrees: undefined,
      uxRefineEnabled: undefined,
      figmaUrl: undefined,
      designTokensPath: undefined,
      mcpHost: undefined,
      designEnabled: undefined,
      designFilePath: undefined,
      designPreviewPath: undefined,
      designTokensSyncedAt: undefined,
      designBackend: undefined,
      designFormatVersion: undefined,
      memoryEnabled: undefined,
      enforcementMode: 'strict',
      autoforgeEnabled: undefined,
      autoforgeFailedAttempts: undefined,
      autoforgeLastRunAt: undefined,
      // v0.8.0 defaults
      projectType: 'unknown',
      qaHealthScore: undefined,
      qaBaseline: undefined,
      qaLastRun: undefined,
      retroDelta: undefined,
      retroLastRun: undefined,
      completionTracker: undefined,
      // v0.9.0 defaults
      reflectionEnabled: undefined,
      reflectionAttempts: undefined,
      reflectionLastVerdict: undefined,
      reflectionScore: undefined,
      premiumTier: undefined,
      premiumLicenseKey: undefined,
      auditTrailEnabled: undefined,
    };
    await saveState(defaultState, options);
    return defaultState;
  }
}

export async function saveState(state: DanteState, options: { cwd?: string } = {}) {
  const { stateDir, stateFile } = resolveStatePaths(options.cwd);
  await fs.mkdir(stateDir, { recursive: true });
  await fs.writeFile(stateFile, yaml.stringify(state));
  logger.info('STATE.yaml updated');
}

// AutoForge — deterministic state machine for auto-orchestrating the DanteForge pipeline
import fs from 'fs/promises';
import { loadState, saveState, type DanteState } from './state.js';
import { enforceWorkflow, getNextSteps, isStageComplete, getCommandStageMap } from './workflow-enforcer.js';
import { getMemoryBudget, getRecentMemory, recordMemory } from './memory-engine.js';
import { logger } from './logger.js';
import { isLLMAvailable } from './llm.js';
import { getProjectCharacteristicsFor } from './mcp-adapter.js';

export type AutoForgeScenario =
  | 'cold-start'
  | 'mid-project'
  | 'stalled'
  | 'frontend'
  | 'multi-session-resume'
  | 'stuck-looping';

export interface AutoForgeStep {
  command: string;
  reason: string;
}

export interface AutoForgePlan {
  scenario: AutoForgeScenario;
  reasoning: string;
  steps: AutoForgeStep[];
  maxWaves: number;
  goal?: string;
}

export interface AutoForgeInput {
  state: DanteState;
  hasDesignOp: boolean;
  hasUI: boolean;
  memoryEntryCount: number;
  lastMemoryAge: number | null; // hours since last memory entry, null if no entries
  failedAttempts: number;
  designViolationCount: number;
}

const CIRCUIT_BREAKER_THRESHOLD = 3;
const STALE_SESSION_HOURS = 24;

/**
 * Gather all inputs needed for AutoForge decision-making.
 */
export async function analyzeProjectState(cwd?: string): Promise<AutoForgeInput> {
  const state = await loadState({ cwd });
  const budget = await getMemoryBudget(cwd);
  const recent = await getRecentMemory(1, cwd);
  const { hasUI, hasDesign } = await getProjectCharacteristicsFor(cwd);

  let lastMemoryAge: number | null = null;
  if (recent.length > 0) {
    const lastTs = new Date(recent[0].timestamp).getTime();
    lastMemoryAge = (Date.now() - lastTs) / (1000 * 60 * 60);
  }

  // Count design violations if .op exists
  let designViolationCount = 0;
  if (hasDesign) {
    try {
      const { parseOP } = await import('../harvested/openpencil/op-codec.js');
      const { evaluateDocument, loadRules, loadRuleConfig } = await import('./design-rules-engine.js');
      const designPath = cwd ? `${cwd}/.danteforge/DESIGN.op` : '.danteforge/DESIGN.op';
      const rulesPath = cwd ? `${cwd}/.danteforge/design-rules.yaml` : '.danteforge/design-rules.yaml';
      const opContent = await fs.readFile(designPath, 'utf8');
      const doc = parseOP(opContent);
      const violations = evaluateDocument(doc, loadRules(rulesPath), loadRuleConfig(rulesPath));
      designViolationCount = violations.filter(v => v.severity === 'error' || v.severity === 'warning').length;
    } catch { /* evaluation failed, skip */ }
  }

  return {
    state,
    hasDesignOp: hasDesign,
    hasUI,
    memoryEntryCount: budget.entryCount,
    lastMemoryAge,
    failedAttempts: state.autoforgeFailedAttempts ?? 0,
    designViolationCount,
  };
}

/**
 * Pure deterministic function — given project input, return a plan.
 * This is NOT an LLM reasoning loop. It's a priority-ordered decision tree.
 */
export function planAutoForge(input: AutoForgeInput, maxWaves = 3, goal?: string): AutoForgePlan {
  const { state, hasDesignOp, hasUI, memoryEntryCount, lastMemoryAge, failedAttempts, designViolationCount } = input;
  const stage = state.workflowStage ?? 'initialized';

  // 1. CIRCUIT BREAKER
  if (failedAttempts >= CIRCUIT_BREAKER_THRESHOLD) {
    return {
      scenario: 'stuck-looping',
      reasoning: `AutoForge has failed ${failedAttempts} consecutive times. Manual intervention required.`,
      steps: [{ command: 'doctor', reason: 'Diagnose the issue before retrying' }],
      maxWaves,
      goal,
    };
  }

  // 2. COLD START
  if (stage === 'initialized' && !hasAnyArtifacts(state)) {
    const steps: AutoForgeStep[] = [
      { command: 'review', reason: 'Scan the codebase to establish baseline' },
      { command: 'constitution', reason: 'Set project principles' },
      { command: 'specify', reason: 'Build the specification' },
      { command: 'clarify', reason: 'Clarify ambiguities in the spec' },
      { command: 'plan', reason: 'Create the implementation plan' },
      { command: 'tasks', reason: 'Break the plan into executable tasks' },
    ];

    if (hasUI) {
      steps.push(
        { command: 'design', reason: 'Generate Design-as-Code (.op) for UI' },
        { command: 'forge', reason: 'Execute the task plan' },
        { command: 'ux-refine', reason: 'Refine UX after forge' },
        { command: 'verify', reason: 'Verify the implementation' },
      );
    } else {
      steps.push(
        { command: 'forge', reason: 'Execute the task plan' },
        { command: 'verify', reason: 'Verify the implementation' },
      );
    }

    return {
      scenario: 'cold-start',
      reasoning: goal
        ? `Fresh project with no artifacts — running full pipeline toward "${goal}".`
        : 'Fresh project with no artifacts — running full pipeline.',
      steps,
      maxWaves,
      goal,
    };
  }

  // 3. TERMINAL STATE
  if (stage === 'synthesize') {
    return {
      scenario: 'mid-project',
      reasoning: 'Workflow is already complete at "synthesize". No further steps are required.',
      steps: [],
      maxWaves,
      goal,
    };
  }

  // 4. MULTI-SESSION RESUME
  if (memoryEntryCount > 0 && lastMemoryAge !== null && lastMemoryAge > STALE_SESSION_HOURS) {
    const resumeSteps: AutoForgeStep[] = [
      { command: 'review', reason: `Last session was ${Math.round(lastMemoryAge)}h ago — refresh codebase state` },
    ];
    // Then fall through to mid-project logic
    resumeSteps.push(...getMidProjectSteps(stage, hasDesignOp, hasUI, designViolationCount));
    return {
      scenario: 'multi-session-resume',
      reasoning: `Last activity was ${Math.round(lastMemoryAge)}h ago. Refreshing state before continuing.`,
      steps: resumeSteps,
      maxWaves,
      goal,
    };
  }

  // 4. STALLED — same stage for too long (would need memory analysis)
  // For deterministic mode, detect via empty next steps
  const nextSteps = getNextSteps(stage);
  if (nextSteps.length === 0) {
    return {
      scenario: 'stalled',
      reasoning: `Workflow is at "${stage}" with no valid next steps. Running doctor.`,
      steps: [{ command: 'doctor', reason: 'Diagnose why the workflow is stuck' }],
      maxWaves,
      goal,
    };
  }

  // 5. FRONTEND — design violations need attention
  if (hasDesignOp && designViolationCount > 0) {
    const frontendSteps: AutoForgeStep[] = [
      { command: 'ux-refine', reason: `${designViolationCount} design violations detected — lint and fix` },
    ];
    frontendSteps.push(...getMidProjectSteps(stage, hasDesignOp, hasUI, 0));
    return {
      scenario: 'frontend',
      reasoning: `Design file has ${designViolationCount} violations. Running UX lint before continuing.`,
      steps: frontendSteps,
      maxWaves,
      goal,
    };
  }

  // 6. MID-PROJECT — determine next step from workflow graph
  const midSteps = getMidProjectSteps(stage, hasDesignOp, hasUI, designViolationCount);
  if (midSteps.length > 0) {
    return {
      scenario: 'mid-project',
      reasoning: goal
        ? `Project at "${stage}" stage — advancing toward "${goal}".`
        : `Project at "${stage}" stage — advancing to next steps.`,
      steps: midSteps,
      maxWaves,
      goal,
    };
  }

  // 7. DEFAULT
  return {
    scenario: 'mid-project',
    reasoning: 'Could not determine optimal path. Running doctor for diagnostics.',
    steps: [{ command: 'doctor', reason: 'Fallback diagnostic' }],
    maxWaves,
    goal,
  };
}

/**
 * Execute an AutoForge plan step by step.
 * Pauses at maxWaves for a human checkpoint.
 */
export async function executeAutoForgePlan(
  plan: AutoForgePlan,
  options: {
    dryRun?: boolean;
    light?: boolean;
    cwd?: string;
    profile?: string;
    parallel?: boolean;
    worktree?: boolean;
    /** Injected for testing — replaces runAutoForgeStep to avoid real CLI execution */
    _runStep?: (command: string, light?: boolean, goal?: string, runtime?: { profile?: string; parallel?: boolean; worktree?: boolean }) => Promise<void>;
    /** Injected for testing — replaces isStageComplete to avoid real fs artifact check */
    _isStageComplete?: (stage: string, cwd?: string) => Promise<boolean>;
  } = {},
): Promise<{ completed: string[]; failed: string[]; paused: boolean }> {
  const completed: string[] = [];
  const failed: string[] = [];
  const runStep = options._runStep ?? runAutoForgeStep;
  const checkStageComplete = options._isStageComplete ?? isStageComplete;

  if (options.dryRun) {
    logger.info('[AutoForge] DRY RUN — no commands will be executed');
    displayPlan(plan);
    return { completed: [], failed: [], paused: false };
  }

  const llmReady = await isLLMAvailable();
  if (!llmReady) {
    logger.warn('[AutoForge] No LLM provider available. Some steps may fail.');
  }

  logger.success(`[AutoForge] Scenario: ${plan.scenario}`);
  logger.info(`[AutoForge] ${plan.reasoning}`);
  logger.info(`[AutoForge] ${plan.steps.length} step(s) planned, max ${plan.maxWaves} waves`);
  logger.info('');

  let wavesExecuted = 0;

  for (const step of plan.steps) {
    if (wavesExecuted >= plan.maxWaves) {
      logger.info(`[AutoForge] Checkpoint: completed ${wavesExecuted} waves. Pausing for review.`);
      return { completed, failed, paused: true };
    }

    logger.info(`[AutoForge] Step: ${step.command} — ${step.reason}`);

    // Best-effort complexity assessment before step execution.
    try {
      const { assessComplexity, formatAssessment } = await import('./complexity-classifier.js');
      const state = await loadState({ cwd: options.cwd });
      const tasks = Object.values(state.tasks).flat();
      if (tasks.length > 0) {
        const assessment = assessComplexity(tasks, state);
        logger.info(`[AutoForge] ${formatAssessment(assessment)}`);
      }
    } catch (err) { logger.verbose(`[best-effort] classifier: ${err instanceof Error ? err.message : String(err)}`); }

    try {
      // v0.10.0 — removed exitCode save/restore pattern (concurrency bug).
      // runStep throws on failure; we catch below. Artifact check provides belt-and-suspenders.
      await runStep(step.command, options.light, plan.goal, {
        profile: options.profile,
        parallel: options.parallel,
        worktree: options.worktree,
      });

      // Verify the step's expected artifact was actually written to disk
      const stageMap = getCommandStageMap();
      const stepStage = stageMap[step.command];
      if (stepStage) {
        const artifactExists = await checkStageComplete(stepStage, options.cwd);
        if (!artifactExists) {
          throw new Error(`${step.command} reported success but its expected artifact is missing from disk`);
        }
      }

      completed.push(step.command);
      wavesExecuted++;
      logger.success(`[AutoForge] ${step.command} complete`);

      // Score artifacts and update completion tracker after each step
      try {
        const { scoreAllArtifacts, persistScoreResult } = await import('./pdse.js');
        const { computeCompletionTracker, detectProjectType } = await import('./completion-tracker.js');
        const postState = await loadState({ cwd: options.cwd });
        if (!postState.projectType || postState.projectType === 'unknown') {
          postState.projectType = await detectProjectType(options.cwd ?? process.cwd());
        }
        const scores = await scoreAllArtifacts(options.cwd ?? process.cwd(), postState);
        for (const result of Object.values(scores)) {
          await persistScoreResult(result, options.cwd ?? process.cwd());
        }
        const tracker = computeCompletionTracker(postState, scores);
        postState.completionTracker = tracker;
        postState.auditLog.push(
          `${new Date().toISOString()} | pdse-score | post-${step.command} overall: ${tracker.overall}%`,
        );
        await saveState(postState, { cwd: options.cwd });

        // Feed PDSE results to model profile engine (best-effort, non-blocking)
        try {
          const { ModelProfileEngine } = await import('./model-profile-engine.js');
          const { resolveProvider } = await import('./config.js');
          const providerInfo = await resolveProvider();
          const modelKey = `${providerInfo.provider}:${providerInfo.model}`;
          const profileEngine = new ModelProfileEngine(options.cwd ?? process.cwd());
          for (const [artifact, scoreResult] of Object.entries(scores)) {
            await profileEngine.recordResult({
              modelKey,
              providerId: providerInfo.provider,
              modelId: providerInfo.model,
              taskDescription: `${artifact} artifact — post-${step.command}`,
              taskCategories: ['configuration'],
              pdseScore: scoreResult.score,
              passed: scoreResult.autoforgeDecision === 'advance',
              antiStubViolations: 0,
              tokensUsed: 0,
              retriesNeeded: 0,
            });
          }
        } catch (err) { logger.verbose(`[best-effort] model profile: ${err instanceof Error ? err.message : String(err)}`); }

        // Best-effort complexity outcome recording for calibration feedback.
        try {
          const { recordComplexityOutcome, assessComplexity: assess, mapScoreToPreset, adjustWeightsFromOutcome, persistComplexityWeights } = await import('./complexity-classifier.js');
          const tasks = Object.values(postState.tasks).flat();
          if (tasks.length > 0) {
            const assessment = assess(tasks, postState);
            // Determine actual preset: user-specified profile if valid, else classifier recommendation
            const validPresets = ['spark', 'ember', 'magic', 'blaze', 'inferno'] as const;
            const actualPreset = validPresets.includes(options.profile as typeof validPresets[number])
              ? (options.profile as typeof validPresets[number])
              : mapScoreToPreset(assessment.score);
            const lesson = recordComplexityOutcome(assessment, actualPreset, assessment.estimatedCostUsd);
            if (lesson) {
              logger.info(`[AutoForge] Complexity calibration: ${lesson}`);
              postState.auditLog.push(
                `${new Date().toISOString()} | complexity-calibration | ${lesson}`,
              );
              await saveState(postState, { cwd: options.cwd });
              // Close the feedback loop: adjust weights and persist
              const { loadComplexityWeights } = await import('./complexity-classifier.js');
              const currentWeights = await loadComplexityWeights(options.cwd);
              const adjusted = adjustWeightsFromOutcome(
                currentWeights,
                assessment.recommendedPreset,
                actualPreset,
              );
              if (adjusted) {
                await persistComplexityWeights(adjusted, options.cwd);
              }
            }
          }
        } catch (err) { logger.verbose(`[best-effort] calibration: ${err instanceof Error ? err.message : String(err)}`); }
      } catch (err) { logger.verbose(`[best-effort] scoring: ${err instanceof Error ? err.message : String(err)}`); }

      await recordMemory({
        category: 'command',
        summary: `AutoForge executed: ${step.command}`,
        detail: `Scenario: ${plan.scenario}. Reason: ${step.reason}${plan.goal ? `. Goal: ${plan.goal}` : ''}`,
        tags: ['autoforge', step.command],
        relatedCommands: [step.command],
      }, options.cwd);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      failed.push(step.command);
      logger.error(`[AutoForge] ${step.command} failed: ${msg}`);

      // 7 Levels Deep root cause analysis for significant forge/verify failures
      if (step.command === 'verify' || step.command === 'forge') {
        try {
          const { SevenLevelsEngine, shouldTriggerSevenLevels } = await import('./seven-levels.js');
          const { recordRootCauseLesson } = await import('./lessons-index.js');
          if (shouldTriggerSevenLevels(undefined, 80)) {
            const engine = new SevenLevelsEngine({ minDepth: 3, earlyStop: true });
            const analysis = await engine.analyze(
              { type: 'step_failure', details: msg },
              {
                taskDescription: step.reason,
                generatedCode: '',
                systemPrompt: '',
                modelId: 'autoforge',
                providerId: 'unknown',
              },
            );
            await recordRootCauseLesson(analysis, options.cwd);
            logger.info(`[7LD] Root cause (${analysis.rootCauseDomain}): ${analysis.rootCause.slice(0, 120)}`);
          }
        } catch (err) { logger.verbose(`[best-effort] 7LD analysis: ${err instanceof Error ? err.message : String(err)}`); }
      }

      // Record failure
      await recordMemory({
        category: 'error',
        summary: `AutoForge failed at: ${step.command}`,
        detail: `Error: ${msg}. Scenario: ${plan.scenario}${plan.goal ? `. Goal: ${plan.goal}` : ''}`,
        tags: ['autoforge', 'failure', step.command],
        relatedCommands: [step.command],
      }, options.cwd);

      // Increment failed attempts
      const state = await loadState({ cwd: options.cwd });
      state.autoforgeFailedAttempts = (state.autoforgeFailedAttempts ?? 0) + 1;
      await saveState(state, { cwd: options.cwd });

      break; // Stop on first failure
    }
  }

  // Reset failed attempts on success
  if (failed.length === 0) {
    const state = await loadState({ cwd: options.cwd });
    state.autoforgeFailedAttempts = 0;
    state.autoforgeLastRunAt = new Date().toISOString();
    await saveState(state, { cwd: options.cwd });
  }

  return { completed, failed, paused: false };
}

/**
 * Display a plan in human-readable format.
 */
export function displayPlan(plan: AutoForgePlan): void {
  logger.info('');
  logger.success('=== AutoForge Plan ===');
  logger.info(`Scenario: ${plan.scenario}`);
  if (plan.goal) {
    logger.info(`Goal: ${plan.goal}`);
  }
  logger.info(`Reasoning: ${plan.reasoning}`);
  logger.info(`Max waves: ${plan.maxWaves}`);
  logger.info('');
  logger.info('Steps:');
  for (let i = 0; i < plan.steps.length; i++) {
    const step = plan.steps[i];
    logger.info(`  ${i + 1}. ${step.command} — ${step.reason}`);
  }
  logger.info('');
}

// Helpers

function hasAnyArtifacts(state: DanteState): boolean {
  // Check if project has moved beyond initialized
  return !!(state.constitution || state.workflowStage !== 'initialized' ||
    Object.keys(state.tasks).length > 0);
}

function getMidProjectSteps(
  stage: string,
  hasDesignOp: boolean,
  hasUI: boolean,
  designViolationCount: number,
): AutoForgeStep[] {
  const steps: AutoForgeStep[] = [];

  switch (stage) {
    case 'initialized':
    case 'review':
      steps.push({ command: 'constitution', reason: 'Establish project principles' });
      break;
    case 'constitution':
      steps.push({ command: 'specify', reason: 'Build the specification' });
      break;
    case 'specify':
      steps.push({ command: 'clarify', reason: 'Clarify spec ambiguities' });
      break;
    case 'clarify':
      steps.push({ command: 'plan', reason: 'Create the implementation plan' });
      break;
    case 'plan':
      steps.push({ command: 'tasks', reason: 'Break the plan into tasks' });
      break;
    case 'tasks':
      if (hasUI && !hasDesignOp) {
        steps.push({ command: 'design', reason: 'UI project needs Design-as-Code' });
      }
      steps.push({ command: 'forge', reason: 'Execute tasks' });
      break;
    case 'design':
      steps.push({ command: 'forge', reason: 'Execute tasks after design' });
      break;
    case 'forge':
      if (hasDesignOp && designViolationCount > 0) {
        steps.push({ command: 'ux-refine', reason: 'Refine UX after forge' });
      }
      steps.push({ command: 'verify', reason: 'Verify the implementation' });
      break;
    case 'ux-refine':
      steps.push({ command: 'verify', reason: 'Verify after UX refinement' });
      break;
    case 'verify':
      steps.push({ command: 'synthesize', reason: 'Generate final summary' });
      break;
    case 'synthesize':
      // Pipeline complete
      break;
  }

  return steps;
}

async function runAutoForgeStep(
  command: string,
  light?: boolean,
  goal?: string,
  runtime: { profile?: string; parallel?: boolean; worktree?: boolean } = {},
): Promise<void> {
  await enforceWorkflow(command, undefined, Boolean(light));

  switch (command) {
    case 'review': {
      const { review } = await import('../cli/commands/review.js');
      await review({ prompt: false });
      return;
    }
    case 'constitution': {
      const { constitution } = await import('../cli/commands/constitution.js');
      await constitution();
      return;
    }
    case 'specify': {
      const { specify } = await import('../cli/commands/specify.js');
      await specify(goal ?? 'AutoForge: continue from current spec');
      return;
    }
    case 'clarify': {
      const { clarify } = await import('../cli/commands/clarify.js');
      await clarify();
      return;
    }
    case 'plan': {
      const { plan } = await import('../cli/commands/plan.js');
      await plan();
      return;
    }
    case 'tasks': {
      const { tasks } = await import('../cli/commands/tasks.js');
      await tasks();
      return;
    }
    case 'design': {
      const { design } = await import('../cli/commands/design.js');
      await design(goal ? `AutoForge: ${goal}` : 'AutoForge: generate design for current spec');
      return;
    }
    case 'forge': {
      const { forge } = await import('../cli/commands/forge.js');
      await forge('1', {
        profile: runtime.profile ?? 'balanced',
        parallel: runtime.parallel,
        worktree: runtime.worktree,
      });
      return;
    }
    case 'ux-refine': {
      const { uxRefine } = await import('../cli/commands/ux-refine.js');
      await uxRefine({ magic: true, afterForge: true });
      return;
    }
    case 'verify': {
      const { verify } = await import('../cli/commands/verify.js');
      await verify();
      return;
    }
    case 'synthesize': {
      const { synthesize } = await import('../cli/commands/synthesize.js');
      await synthesize();
      return;
    }
    case 'doctor': {
      const { doctor } = await import('../cli/commands/doctor.js');
      await doctor();
      return;
    }
    default:
      throw new Error(`Unknown autoforge step: ${command}`);
  }
}

// Workflow Enforcer — mandatory state machine for DanteForge pipeline transitions
import { loadState } from './state.js';
import {
  requireConstitution,
  requireSpec,
  requireClarify,
  requirePlan,
  requireTests,
  GateError,
} from './gates.js';
import { logger } from './logger.js';
import type { WorkflowStage } from './state.js';

export interface WorkflowTransition {
  from: WorkflowStage[];
  to: WorkflowStage;
  gates: ((light?: boolean) => Promise<void>)[];
  artifacts: string[];
}

const WORKFLOW_GRAPH: WorkflowTransition[] = [
  { from: ['initialized'], to: 'review', gates: [], artifacts: ['CURRENT_STATE.md'] },
  { from: ['initialized', 'review'], to: 'constitution', gates: [], artifacts: ['CONSTITUTION.md'] },
  { from: ['constitution'], to: 'specify', gates: [requireConstitution], artifacts: ['SPEC.md'] },
  { from: ['specify'], to: 'clarify', gates: [requireSpec], artifacts: ['CLARIFY.md'] },
  { from: ['clarify', 'specify'], to: 'plan', gates: [requireSpec], artifacts: ['PLAN.md'] },
  { from: ['plan'], to: 'tasks', gates: [requirePlan], artifacts: ['TASKS.md'] },
  { from: ['tasks', 'plan'], to: 'design', gates: [requirePlan], artifacts: ['DESIGN.op'] },
  { from: ['tasks', 'design'], to: 'forge', gates: [requirePlan, requireTests], artifacts: [] },
  { from: ['forge'], to: 'ux-refine', gates: [], artifacts: [] },
  { from: ['forge', 'ux-refine'], to: 'verify', gates: [], artifacts: [] },
  { from: ['verify'], to: 'synthesize', gates: [], artifacts: ['UPR.md'] },
];

// Map command names to their target workflow stages
const COMMAND_STAGE_MAP: Record<string, WorkflowStage> = {
  review: 'review',
  constitution: 'constitution',
  specify: 'specify',
  clarify: 'clarify',
  plan: 'plan',
  tasks: 'tasks',
  design: 'design',
  forge: 'forge',
  'ux-refine': 'ux-refine',
  verify: 'verify',
  synthesize: 'synthesize',
};

export interface TransitionResult {
  valid: boolean;
  blocked: GateError[];
  transition?: WorkflowTransition;
}

/**
 * Check if a transition from current stage to target stage is allowed.
 */
export async function validateTransition(
  currentStage: WorkflowStage,
  targetStage: WorkflowStage,
  light = false,
): Promise<TransitionResult> {
  // Find matching transition in the graph
  const transition = WORKFLOW_GRAPH.find(
    t => t.to === targetStage && t.from.includes(currentStage),
  );

  if (!transition) {
    // Check if there's ANY transition to this target (wrong source stage)
    const anyTransition = WORKFLOW_GRAPH.find(t => t.to === targetStage);
    if (anyTransition) {
      return {
        valid: false,
        blocked: [
          new GateError(
            `Cannot transition from '${currentStage}' to '${targetStage}'. Valid source stages: ${anyTransition.from.join(', ')}`,
            'workflow-enforcer',
            `Complete the '${anyTransition.from[anyTransition.from.length - 1]}' stage first.`,
          ),
        ],
      };
    }
    return {
      valid: false,
      blocked: [
        new GateError(
          `Unknown workflow target: '${targetStage}'`,
          'workflow-enforcer',
          'Run "danteforge help" to see the workflow pipeline.',
        ),
      ],
    };
  }

  // In light mode, skip gate checks but still validate the graph edge
  if (light) {
    return { valid: true, blocked: [], transition };
  }

  // Run all gates for this transition
  const blocked: GateError[] = [];
  for (const gateFn of transition.gates) {
    try {
      await gateFn(false);
    } catch (err) {
      if (err instanceof GateError) {
        blocked.push(err);
      } else {
        throw err;
      }
    }
  }

  return {
    valid: blocked.length === 0,
    blocked,
    transition,
  };
}

/**
 * Enforce workflow transition at the top of a CLI command.
 * In 'advisory' mode: logs warnings but allows execution.
 * In 'strict' mode: blocks execution on gate failure.
 */
export async function enforceWorkflow(
  command: string,
  targetStage?: WorkflowStage,
  light = false,
  cwd?: string,
): Promise<void> {
  if (command === 'verify' || command === 'ux-refine') {
    return;
  }

  const target = targetStage ?? COMMAND_STAGE_MAP[command];
  if (!target) return; // Command not in workflow graph (e.g., config, doctor)

  if (light) return;

  const state = await loadState({ cwd });
  const currentStage = state.workflowStage;
  const enforcementMode = state.enforcementMode ?? 'strict';

  // Same stage or re-running is always allowed
  if (currentStage === target) return;

  // Allow review to reset stale execution sessions once task execution has started.
  if (target === 'review' && state.currentPhase > 0) {
    return;
  }

  const result = await validateTransition(currentStage, target, light);

  if (result.valid) return;

  // Report gate failures
  for (const err of result.blocked) {
    logger.error(err.message);
    logger.info(`Remedy: ${err.remedy}`);
  }

  if (enforcementMode === 'strict' && !light) {
    throw new GateError(
      `Workflow blocked: cannot run '${command}' from stage '${currentStage}'`,
      'workflow-enforcer',
      result.blocked.map(e => e.remedy).join('; '),
    );
  }

  // Advisory mode — warn but proceed
  logger.warn(`Workflow advisory: '${command}' is running outside the expected sequence (current: ${currentStage})`);
}

/**
 * Get valid next workflow stages from the current position.
 */
export function getNextSteps(currentStage: WorkflowStage): WorkflowStage[] {
  return WORKFLOW_GRAPH
    .filter(t => t.from.includes(currentStage))
    .map(t => t.to);
}

/**
 * Check if all artifacts for a given stage exist.
 */
export async function isStageComplete(stage: WorkflowStage, cwd?: string): Promise<boolean> {
  const transition = WORKFLOW_GRAPH.find(t => t.to === stage);
  if (!transition || transition.artifacts.length === 0) return true;

  const fs = await import('fs/promises');
  const path = await import('path');
  const stateDir = path.join(cwd ?? process.cwd(), '.danteforge');

  for (const artifact of transition.artifacts) {
    try {
      await fs.access(path.join(stateDir, artifact));
    } catch {
      return false;
    }
  }
  return true;
}

/**
 * Get the full workflow graph for introspection (used by autoforge, doctor, help).
 */
export function getWorkflowGraph(): WorkflowTransition[] {
  return [...WORKFLOW_GRAPH];
}

/**
 * Get the command-to-stage mapping.
 */
export function getCommandStageMap(): Record<string, WorkflowStage> {
  return { ...COMMAND_STAGE_MAP };
}

// Hard Gates — mandatory checkpoints that block progression until prerequisites are met
import fs from 'fs/promises';
import path from 'path';
import { loadState } from './state.js';
import { logger } from './logger.js';
import { detectLoop } from './loop-detector.js';
import { detectAIDrift } from './drift-detector.js';
import { loadLatestVerdict } from './reflection-engine.js';
import type { ExecutionTelemetry } from './execution-telemetry.js';

const STATE_DIR = '.danteforge';

async function fileExists(filePath: string): Promise<boolean> {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

export class GateError extends Error {
  constructor(
    message: string,
    public readonly gate: string,
    public readonly remedy: string,
  ) {
    super(message);
    this.name = 'GateError';
  }
}

/**
 * Gate: Constitution must exist before spec/clarify/plan
 */
export async function requireConstitution(light = false, cwd?: string): Promise<void> {
  if (light) return;
  const base = cwd ?? process.cwd();
  const state = await loadState({ cwd });
  if (!state.constitution || !(await fileExists(path.join(base, STATE_DIR, 'CONSTITUTION.md')))) {
    throw new GateError(
      'Gate blocked: No constitution defined.',
      'requireConstitution',
      'Run "danteforge constitution" first to establish project principles.',
    );
  }
}

/**
 * Gate: SPEC.md must exist before plan/tasks
 */
export async function requireSpec(light = false, cwd?: string): Promise<void> {
  if (light) return;
  const base = cwd ?? process.cwd();
  if (!(await fileExists(path.join(base, STATE_DIR, 'SPEC.md')))) {
    throw new GateError(
      'Gate blocked: No SPEC.md found.',
      'requireSpec',
      'Run "danteforge specify <idea>" first to generate spec artifacts.',
    );
  }
}

/**
 * Gate: CLARIFY.md must exist before plan generation
 */
export async function requireClarify(light = false, cwd?: string): Promise<void> {
  if (light) return;
  const base = cwd ?? process.cwd();
  if (!(await fileExists(path.join(base, STATE_DIR, 'CLARIFY.md')))) {
    throw new GateError(
      'Gate blocked: No CLARIFY.md found.',
      'requireClarify',
      'Run "danteforge clarify" first to resolve requirement gaps before planning.',
    );
  }
}

/**
 * Gate: PLAN.md must exist before forge/tasks execution
 */
export async function requirePlan(light = false, cwd?: string): Promise<void> {
  if (light) return;
  const base = cwd ?? process.cwd();
  if (!(await fileExists(path.join(base, STATE_DIR, 'PLAN.md')))) {
    throw new GateError(
      'Gate blocked: No PLAN.md found.',
      'requirePlan',
      'Run "danteforge plan" first to generate an execution plan.',
    );
  }
}

/**
 * Gate: Tests must exist before production code generation (TDD enforcement)
 */
export async function requireTests(light = false, cwd?: string): Promise<void> {
  if (light) return;
  const base = cwd ?? process.cwd();
  const state = await loadState({ cwd });
  if (!state.tddEnabled) return; // TDD gate only active when explicitly enabled

  // Check for any test files in the project
  const testDirs = ['tests', 'test', '__tests__', 'spec'];
  let hasTests = false;

  for (const dir of testDirs) {
    const testDirPath = path.join(base, dir);
    if (await fileExists(testDirPath)) {
      const entries = await fs.readdir(testDirPath);
      if (entries.some(e => e.includes('.test.') || e.includes('.spec.'))) {
        hasTests = true;
        break;
      }
    }
  }

  if (!hasTests) {
    throw new GateError(
      'Gate blocked: TDD mode is enabled but no test files found.',
      'requireTests',
      'Write tests first (RED phase), then run forge. See: test-driven-development skill.',
    );
  }
}

/**
 * Gate: DESIGN.op must exist before design-dependent commands
 */
export async function requireDesign(light = false, cwd?: string): Promise<void> {
  if (light) return;
  const base = cwd ?? process.cwd();
  const designPath = path.join(base, STATE_DIR, 'DESIGN.op');
  if (!(await fileExists(designPath))) {
    throw new GateError(
      'Gate blocked: No DESIGN.op found.',
      'requireDesign',
      'Run "danteforge design <prompt>" first to generate design artifacts.',
    );
  }
  // Validate JSON structure
  try {
    const content = await fs.readFile(designPath, 'utf8');
    const parsed = JSON.parse(content);
    if (!parsed.nodes || !parsed.document) {
      throw new Error('Missing required .op fields: nodes, document');
    }
  } catch (err) {
    if (err instanceof GateError) throw err;
    throw new GateError(
      `Gate blocked: DESIGN.op is malformed — ${err instanceof Error ? err.message : String(err)}`,
      'requireDesign',
      'Regenerate with: danteforge design <prompt>',
    );
  }
}

/**
 * Gate: Generic approval gate for human-in-the-loop
 */
export async function requireApproval(artifact: string, light = false): Promise<void> {
  if (light) return;
  // In CLI mode, this logs a warning — actual blocking is done by the caller
  logger.warn(`Approval gate: "${artifact}" requires human review before proceeding.`);
}

/**
 * Gate: No execution loops detected (v0.9.0 — Reflection Engine)
 */
export async function requireNoLoops(telemetry: ExecutionTelemetry, light = false): Promise<void> {
  if (light) return;
  const result = detectLoop(telemetry);
  if (result.detected && result.severity === 'HIGH') {
    throw new GateError(
      `Gate blocked: ${result.type} loop detected — ${result.evidence}`,
      'requireNoLoops',
      result.type === 'planning'
        ? 'Stop reading files and start writing code. You have enough context.'
        : 'Stop repeating the same commands. Try a different approach or ask for help.',
    );
  }
}

/**
 * Gate: Reflection score meets minimum threshold (v0.9.0 — Reflection Engine)
 */
export async function requireReflectionScore(minScore: number, light = false): Promise<void> {
  if (light) return;
  const verdict = await loadLatestVerdict();
  if (!verdict) return; // No reflection data yet — don't block
  const { evaluateVerdict } = await import('./reflection-engine.js');
  const evaluation = evaluateVerdict(verdict);
  if (evaluation.score < minScore) {
    throw new GateError(
      `Gate blocked: Reflection score ${evaluation.score} is below minimum ${minScore}.`,
      'requireReflectionScore',
      `Address reflection feedback: ${evaluation.missing.slice(0, 3).join('; ')}`,
    );
  }
}

/**
 * Gate: No BLOCKER-level AI drift violations (v0.9.0 — Reflection Engine)
 */
export async function requireNoDrift(filesModified: string[], light = false): Promise<void> {
  if (light) return;
  if (filesModified.length === 0) return;
  const violations = await detectAIDrift(filesModified);
  const blockers = violations.filter(v => v.severity === 'BLOCKER' || v.severity === 'HIGH');
  if (blockers.length > 0) {
    const details = blockers.slice(0, 3).map(v => `${v.file}:${v.line} — ${v.message}`).join('; ');
    throw new GateError(
      `Gate blocked: ${blockers.length} AI drift violation(s) detected — ${details}`,
      'requireNoDrift',
      'Fix hallucinated imports, remove stubs, and verify API endpoints before proceeding.',
    );
  }
}

/**
 * Run a gate and handle errors gracefully
 */
export async function runGate(gateFn: () => Promise<void>): Promise<boolean> {
  try {
    await gateFn();
    return true;
  } catch (err) {
    if (err instanceof GateError) {
      logger.error(`${err.message}`);
      logger.info(`Remedy: ${err.remedy}`);
      return false;
    }
    throw err;
  }
}

// Loop Detector — detects planning loops and action loops in agent execution
// Harvested from: Reflection-3.ts (OpenCode plugin) — planning loop + action loop detection

import type { ExecutionTelemetry } from './execution-telemetry.js';

// --- Constants (from Reflection-3.ts) ----------------------------------------

const PLANNING_LOOP_MIN_TOOL_CALLS = 8;
const PLANNING_LOOP_WRITE_RATIO_THRESHOLD = 0.1;
const ACTION_LOOP_MIN_COMMANDS = 4;
const ACTION_LOOP_REPETITION_THRESHOLD = 0.6;
const ACTION_LOOP_MIN_REPEATS = 3;

// --- Types -------------------------------------------------------------------

export type LoopType = 'planning' | 'action' | 'none';
export type LoopSeverity = 'LOW' | 'MEDIUM' | 'HIGH';

export interface LoopDetectionResult {
  detected: boolean;
  type: LoopType;
  evidence: string;
  severity: LoopSeverity;
}

const NO_LOOP: LoopDetectionResult = {
  detected: false,
  type: 'none',
  evidence: '',
  severity: 'LOW',
};

// --- Planning Loop Detection -------------------------------------------------
// From Reflection-3.ts: Agent is stuck in read-only mode (many tool calls, few writes)
// Triggers when: totalTools >= 8 AND writeCount/totalTools < 0.1

export function detectPlanningLoop(telemetry: ExecutionTelemetry): LoopDetectionResult {
  const total = telemetry.toolCalls.length;
  if (total < PLANNING_LOOP_MIN_TOOL_CALLS) return NO_LOOP;

  const writes = telemetry.toolCalls.filter(tc => tc.isWrite).length;
  const writeRatio = total > 0 ? writes / total : 0;

  if (writes === 0 || writeRatio < PLANNING_LOOP_WRITE_RATIO_THRESHOLD) {
    const severity: LoopSeverity = writes === 0 ? 'HIGH' : 'MEDIUM';
    return {
      detected: true,
      type: 'planning',
      evidence: `${total} tool calls but only ${writes} writes (ratio: ${writeRatio.toFixed(2)}). Agent is reading without acting.`,
      severity,
    };
  }

  return NO_LOOP;
}

// --- Action Loop Detection ---------------------------------------------------
// From Reflection-3.ts: Agent is repeating the same failing commands
// Triggers when: any command repeated >=3x AND repeated >=60% of total

function normalizeCommand(cmd: string): string {
  return cmd
    .replace(/\s+/g, ' ')
    .replace(/\d{10,}/g, '<timestamp>')
    .replace(/\/tmp\/[^\s]+/g, '<tmpfile>')
    .trim()
    .toLowerCase();
}

export function detectActionLoop(telemetry: ExecutionTelemetry): LoopDetectionResult {
  const commands = telemetry.bashCommands;
  if (commands.length < ACTION_LOOP_MIN_COMMANDS) return NO_LOOP;

  const normalized = commands.map(normalizeCommand);
  const counts = new Map<string, number>();

  for (const cmd of normalized) {
    counts.set(cmd, (counts.get(cmd) ?? 0) + 1);
  }

  let totalRepeated = 0;
  let mostRepeated = '';
  let mostRepeatedCount = 0;

  for (const [cmd, count] of counts) {
    if (count >= ACTION_LOOP_MIN_REPEATS) {
      totalRepeated += count;
      if (count > mostRepeatedCount) {
        mostRepeated = cmd;
        mostRepeatedCount = count;
      }
    }
  }

  const repetitionRatio = commands.length > 0 ? totalRepeated / commands.length : 0;

  if (mostRepeatedCount >= ACTION_LOOP_MIN_REPEATS && repetitionRatio >= ACTION_LOOP_REPETITION_THRESHOLD) {
    return {
      detected: true,
      type: 'action',
      evidence: `Command "${mostRepeated}" repeated ${mostRepeatedCount}x out of ${commands.length} total (${(repetitionRatio * 100).toFixed(0)}% repetition).`,
      severity: repetitionRatio > 0.8 ? 'HIGH' : 'MEDIUM',
    };
  }

  return NO_LOOP;
}

// --- Combined Detector -------------------------------------------------------

export function detectLoop(telemetry: ExecutionTelemetry): LoopDetectionResult {
  const planning = detectPlanningLoop(telemetry);
  const action = detectActionLoop(telemetry);

  // Return the more severe result
  if (!planning.detected && !action.detected) return NO_LOOP;
  if (!planning.detected) return action;
  if (!action.detected) return planning;

  const severityOrder: Record<LoopSeverity, number> = { LOW: 0, MEDIUM: 1, HIGH: 2 };
  return severityOrder[action.severity] >= severityOrder[planning.severity] ? action : planning;
}

// Drift Detector — detects AI-specific code quality issues
// Harvested from: Rigour (rigour-labs) — hallucinated imports, stub patterns, phantom APIs
// Uses regex + file system checks (zero AST dependencies)

import fs from 'fs/promises';
import path from 'path';
import type { Violation, ViolationSeverity } from './fix-packet.js';

// --- Patterns ----------------------------------------------------------------

const STUB_PATTERNS = [
  { pattern: /\bTODO\b/g, label: 'TODO marker' },
  { pattern: /\bFIXME\b/g, label: 'FIXME marker' },
  { pattern: /\bnot\s+implemented\b/i, label: 'Not implemented placeholder' },
  { pattern: /\bplaceholder\b/i, label: 'Placeholder text' },
  { pattern: /throw\s+new\s+Error\s*\(\s*['"`](?:TODO|not implemented|implement me)/i, label: 'Stub throw' },
];

const IMPORT_PATTERNS = [
  // ESM: import X from 'Y' or import { X } from 'Y'
  /import\s+(?:(?:\{[^}]*\}|\*\s+as\s+\w+|\w+)\s+from\s+)?['"]([^'"./][^'"]*)['"]/g,
  // CJS: require('Y')
  /require\s*\(\s*['"]([^'"./][^'"]*)['"]\s*\)/g,
];

const PHANTOM_API_PATTERNS = [
  /fetch\s*\(\s*['"`](https?:\/\/[^'"` ]+)['"`]/g,
  /axios\s*\.\s*(?:get|post|put|delete|patch)\s*\(\s*['"`](https?:\/\/[^'"` ]+)['"`]/g,
];

const CODE_EXTENSIONS = new Set(['.ts', '.tsx', '.js', '.jsx', '.mjs', '.cjs']);

// --- Helpers -----------------------------------------------------------------

async function fileExists(filePath: string): Promise<boolean> {
  try {
    await fs.access(filePath);
    return true;
  } catch {
    return false;
  }
}

async function isBuiltinOrScoped(pkg: string): Promise<boolean> {
  // Node.js builtins
  if (pkg.startsWith('node:') || ['fs', 'path', 'os', 'url', 'util', 'http', 'https',
    'crypto', 'stream', 'events', 'child_process', 'assert', 'buffer', 'querystring',
    'readline', 'zlib', 'net', 'tls', 'dns', 'dgram', 'cluster', 'worker_threads',
    'perf_hooks', 'test', 'v8', 'vm', 'tty'].includes(pkg)) {
    return true;
  }
  return false;
}

function extractPackageName(importPath: string): string {
  // @scoped/package → @scoped/package
  // package/subpath → package
  if (importPath.startsWith('@')) {
    const parts = importPath.split('/');
    return parts.length >= 2 ? `${parts[0]}/${parts[1]}` : importPath;
  }
  return importPath.split('/')[0]!;
}

// --- Detectors ---------------------------------------------------------------

async function detectHallucinatedImports(
  filePath: string,
  content: string,
  cwd: string,
): Promise<Violation[]> {
  const violations: Violation[] = [];

  for (const pattern of IMPORT_PATTERNS) {
    const regex = new RegExp(pattern.source, pattern.flags);
    let match: RegExpExecArray | null;

    while ((match = regex.exec(content)) !== null) {
      const rawImport = match[1]!;
      const pkgName = extractPackageName(rawImport);

      if (await isBuiltinOrScoped(pkgName)) continue;

      // Check node_modules
      const nodeModulePath = path.join(cwd, 'node_modules', pkgName);
      if (await fileExists(nodeModulePath)) continue;

      // Check if it's a project-relative path that got confused
      const projectPath = path.join(cwd, rawImport);
      if (await fileExists(projectPath) || await fileExists(`${projectPath}.ts`) || await fileExists(`${projectPath}.js`)) continue;

      const lineNumber = content.substring(0, match.index).split('\n').length;
      violations.push({
        type: 'ai-drift',
        severity: 'HIGH' as ViolationSeverity,
        file: filePath,
        line: lineNumber,
        message: `Hallucinated import: "${rawImport}" not found in node_modules or project`,
        evidence: match[0],
      });
    }
  }

  return violations;
}

function detectStubPatterns(filePath: string, content: string): Violation[] {
  const violations: Violation[] = [];

  for (const { pattern, label } of STUB_PATTERNS) {
    const regex = new RegExp(pattern.source, pattern.flags);
    let match: RegExpExecArray | null;

    while ((match = regex.exec(content)) !== null) {
      const lineNumber = content.substring(0, match.index).split('\n').length;
      violations.push({
        type: 'stub-detected',
        severity: 'MEDIUM' as ViolationSeverity,
        file: filePath,
        line: lineNumber,
        message: `${label} found`,
        evidence: content.split('\n')[lineNumber - 1]?.trim(),
      });
    }
  }

  return violations;
}

function detectPhantomAPIs(filePath: string, content: string): Violation[] {
  const violations: Violation[] = [];

  for (const pattern of PHANTOM_API_PATTERNS) {
    const regex = new RegExp(pattern.source, pattern.flags);
    let match: RegExpExecArray | null;

    while ((match = regex.exec(content)) !== null) {
      const url = match[1]!;
      // Skip well-known API bases
      if (/localhost|127\.0\.0\.1|example\.com|placeholder/i.test(url)) continue;

      const lineNumber = content.substring(0, match.index).split('\n').length;
      violations.push({
        type: 'ai-drift',
        severity: 'MEDIUM' as ViolationSeverity,
        file: filePath,
        line: lineNumber,
        message: `Hardcoded API URL: "${url}" — verify this endpoint exists`,
        evidence: match[0],
      });
    }
  }

  return violations;
}

// --- Public API --------------------------------------------------------------

export async function detectAIDrift(
  filesModified: string[],
  cwd = process.cwd(),
): Promise<Violation[]> {
  const violations: Violation[] = [];

  for (const filePath of filesModified) {
    const ext = path.extname(filePath).toLowerCase();
    if (!CODE_EXTENSIONS.has(ext)) continue;

    const fullPath = path.isAbsolute(filePath) ? filePath : path.join(cwd, filePath);

    let content: string;
    try {
      content = await fs.readFile(fullPath, 'utf8');
    } catch {
      continue; // File may have been deleted or moved
    }

    violations.push(
      ...await detectHallucinatedImports(filePath, content, cwd),
      ...detectStubPatterns(filePath, content),
      ...detectPhantomAPIs(filePath, content),
    );
  }

  return violations;
}

// Reflection Engine — structured self-assessment after every agent turn
// Harvested from: Reflection-3.ts (OpenCode), Ralph Loop (Vercel Labs), Rigour (rigour-labs)
// Produces evidence-based verdicts instead of "trust me bro" claims.

import fs from 'fs/promises';
import path from 'path';
import { logger } from './logger.js';
import { isLLMAvailable, callLLM } from './llm.js';
import { recordMemory } from './memory-engine.js';
import type { ExecutionTelemetry } from './execution-telemetry.js';

const REFLECTIONS_DIR = path.join('.danteforge', 'reflections');

// --- Types -------------------------------------------------------------------

export type ReflectionStatus = 'complete' | 'in_progress' | 'blocked' | 'stuck';
export type Severity = 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH' | 'BLOCKER';

export interface EvidenceGate {
  ran: boolean;
  passed: boolean;
  ranAfterChanges: boolean;
}

export interface ReflectionVerdict {
  sessionId: string;
  taskName: string;
  status: ReflectionStatus;
  confidence: number; // 0.0–1.0
  evidence: {
    tests: EvidenceGate;
    build: EvidenceGate;
    lint: EvidenceGate;
  };
  remainingWork: string[];
  nextSteps: string[];
  needsHumanAction: string[];
  stuck: boolean;
  severity: Severity;
  timestamp: string;
}

export interface ReflectionConfig {
  maxAttempts: number;
  confidenceThreshold: number;
  enableLoopDetection: boolean;
  enableFixPackets: boolean;
}

export interface ReflectionEvaluation {
  complete: boolean;
  missing: string[];
  feedback: string;
  score: number; // 0–100
}

export type ReflectionHook = (verdict: ReflectionVerdict) => Promise<void>;

// --- Defaults ----------------------------------------------------------------

export const DEFAULT_REFLECTION_CONFIG: ReflectionConfig = {
  maxAttempts: 3,
  confidenceThreshold: 0.8,
  enableLoopDetection: true,
  enableFixPackets: true,
};

// --- Hook Registry -----------------------------------------------------------

const hooks: ReflectionHook[] = [];

export function registerHook(hook: ReflectionHook): void {
  hooks.push(hook);
}

export function clearHooks(): void {
  hooks.length = 0;
}

async function runHooks(verdict: ReflectionVerdict): Promise<void> {
  for (const hook of hooks) {
    try {
      await hook(verdict);
    } catch (err) {
      logger.warn(`Reflection hook failed: ${err instanceof Error ? err.message : String(err)}`);
    }
  }
}

// --- Self-Assessment Prompt --------------------------------------------------

function buildSelfAssessmentPrompt(taskName: string, taskOutput: string, telemetry: ExecutionTelemetry): string {
  const telemetrySummary = [
    `Tool calls: ${telemetry.toolCalls.length}`,
    `Writes: ${telemetry.toolCalls.filter(tc => tc.isWrite).length}`,
    `Bash commands: ${telemetry.bashCommands.length}`,
    `Files modified: ${telemetry.filesModified.length}`,
    `Duration: ${(telemetry.duration / 1000).toFixed(1)}s`,
  ].join(', ');

  return `You are a strict code quality reviewer. Assess the following task execution and return ONLY valid JSON (no markdown fences, no explanation).

Task: ${taskName}
Execution telemetry: ${telemetrySummary}
Files modified: ${telemetry.filesModified.join(', ') || 'none'}

Task output (truncated to 2000 chars):
${taskOutput.slice(0, 2000)}

Return this exact JSON structure:
{
  "status": "complete" | "in_progress" | "blocked" | "stuck",
  "confidence": <number 0.0 to 1.0>,
  "evidence": {
    "tests": { "ran": <bool>, "passed": <bool>, "ranAfterChanges": <bool> },
    "build": { "ran": <bool>, "passed": <bool>, "ranAfterChanges": <bool> },
    "lint": { "ran": <bool>, "passed": <bool>, "ranAfterChanges": <bool> }
  },
  "remainingWork": [<string items>],
  "nextSteps": [<string items>],
  "needsHumanAction": [<string items>],
  "stuck": <bool>
}`;
}

// --- Heuristic Fallback ------------------------------------------------------

function heuristicAssessment(taskName: string, taskOutput: string, telemetry: ExecutionTelemetry): ReflectionVerdict {
  const writes = telemetry.toolCalls.filter(tc => tc.isWrite).length;
  const hasOutput = taskOutput.trim().length > 0;
  const mentionsPass = /\bpass(ed)?\b/i.test(taskOutput);
  const mentionsFail = /\bfail(ed|ure)?\b/i.test(taskOutput);
  const mentionsError = /\b(error|exception|crash)\b/i.test(taskOutput);

  let status: ReflectionStatus = 'in_progress';
  let confidence = 0.5;
  const remainingWork: string[] = [];

  if (writes > 0 && hasOutput && mentionsPass && !mentionsFail && !mentionsError) {
    status = 'complete';
    confidence = 0.7;
  } else if (mentionsFail || mentionsError) {
    status = 'blocked';
    confidence = 0.6;
    remainingWork.push('Fix failing tests or errors');
  } else if (writes === 0) {
    status = 'stuck';
    confidence = 0.4;
    remainingWork.push('No write operations detected — task may not have started');
  }

  return {
    sessionId: `heuristic-${Date.now()}`,
    taskName,
    status,
    confidence,
    evidence: {
      tests: { ran: mentionsPass || mentionsFail, passed: mentionsPass && !mentionsFail, ranAfterChanges: false },
      build: { ran: false, passed: false, ranAfterChanges: false },
      lint: { ran: false, passed: false, ranAfterChanges: false },
    },
    remainingWork,
    nextSteps: status === 'complete' ? [] : ['Review task output and retry'],
    needsHumanAction: [],
    stuck: status === 'stuck',
    severity: status === 'complete' ? 'NONE' : status === 'stuck' ? 'HIGH' : 'MEDIUM',
    timestamp: new Date().toISOString(),
  };
}

// --- JSON Parsing ------------------------------------------------------------

function parseVerdictJSON(raw: string): Partial<ReflectionVerdict> | null {
  // Strip markdown code fences if present
  const cleaned = raw.replace(/^```(?:json)?\s*\n?/m, '').replace(/\n?```\s*$/m, '').trim();
  try {
    return JSON.parse(cleaned) as Partial<ReflectionVerdict>;
  } catch {
    // Try to extract JSON from surrounding text
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]) as Partial<ReflectionVerdict>;
      } catch {
        return null;
      }
    }
    return null;
  }
}

function normalizeVerdict(parsed: Partial<ReflectionVerdict>, taskName: string): ReflectionVerdict {
  const defaultGate: EvidenceGate = { ran: false, passed: false, ranAfterChanges: false };
  const evidence = parsed.evidence ?? { tests: defaultGate, build: defaultGate, lint: defaultGate };

  const status = parsed.status ?? 'in_progress';
  const confidence = typeof parsed.confidence === 'number' ? Math.max(0, Math.min(1, parsed.confidence)) : 0.5;

  let severity: Severity = 'NONE';
  if (status === 'stuck') severity = 'HIGH';
  else if (status === 'blocked') severity = 'MEDIUM';
  else if (status === 'in_progress') severity = 'LOW';

  return {
    sessionId: `llm-${Date.now()}`,
    taskName,
    status,
    confidence,
    evidence: {
      tests: { ...defaultGate, ...evidence.tests },
      build: { ...defaultGate, ...evidence.build },
      lint: { ...defaultGate, ...evidence.lint },
    },
    remainingWork: Array.isArray(parsed.remainingWork) ? parsed.remainingWork : [],
    nextSteps: Array.isArray(parsed.nextSteps) ? parsed.nextSteps : [],
    needsHumanAction: Array.isArray(parsed.needsHumanAction) ? parsed.needsHumanAction : [],
    stuck: parsed.stuck ?? (status === 'stuck'),
    severity,
    timestamp: new Date().toISOString(),
  };
}

// --- Persistence -------------------------------------------------------------

async function persistVerdict(verdict: ReflectionVerdict, cwd = process.cwd()): Promise<string> {
  const dir = path.join(cwd, REFLECTIONS_DIR);
  await fs.mkdir(dir, { recursive: true });

  const safeName = verdict.taskName.replace(/[^a-zA-Z0-9-_]/g, '-').slice(0, 60);
  const filename = `${safeName}-${Date.now()}.json`;
  const filePath = path.join(dir, filename);

  await fs.writeFile(filePath, JSON.stringify(verdict, null, 2));
  return filePath;
}

export async function loadLatestVerdict(cwd = process.cwd()): Promise<ReflectionVerdict | null> {
  const dir = path.join(cwd, REFLECTIONS_DIR);
  try {
    const files = (await fs.readdir(dir)).filter(f => f.endsWith('.json')).sort().reverse();
    if (files.length === 0) return null;
    const content = await fs.readFile(path.join(dir, files[0]!), 'utf8');
    return JSON.parse(content) as ReflectionVerdict;
  } catch {
    return null;
  }
}

// --- Core API ----------------------------------------------------------------

export async function reflect(
  taskName: string,
  taskOutput: string,
  telemetry: ExecutionTelemetry,
  options?: { cwd?: string; _llmCaller?: (prompt: string) => Promise<string> },
): Promise<ReflectionVerdict> {
  const cwd = options?.cwd;
  logger.info(`Reflecting on: ${taskName}`);

  let verdict: ReflectionVerdict;
  const llmReady = options?._llmCaller != null || await isLLMAvailable();

  if (llmReady) {
    try {
      const prompt = buildSelfAssessmentPrompt(taskName, taskOutput, telemetry);
      const response = options?._llmCaller
        ? await options._llmCaller(prompt)
        : await callLLM(prompt, undefined, { recordMemory: false });
      const parsed = parseVerdictJSON(response);

      if (parsed) {
        verdict = normalizeVerdict(parsed, taskName);
      } else {
        logger.warn('Reflection: LLM response was not valid JSON — falling back to heuristics');
        verdict = heuristicAssessment(taskName, taskOutput, telemetry);
      }
    } catch (err) {
      logger.warn(`Reflection LLM call failed: ${err instanceof Error ? err.message : String(err)}`);
      verdict = heuristicAssessment(taskName, taskOutput, telemetry);
    }
  } else {
    verdict = heuristicAssessment(taskName, taskOutput, telemetry);
  }

  // Persist
  const verdictPath = await persistVerdict(verdict, cwd);
  logger.info(`Reflection verdict: ${verdict.status} (confidence: ${verdict.confidence}, severity: ${verdict.severity})`);

  // Record to memory if issues found
  if (verdict.severity !== 'NONE') {
    await recordMemory({
      category: 'insight',
      summary: `Reflection on "${taskName}": ${verdict.status} (${verdict.severity})`,
      detail: `Confidence: ${verdict.confidence}, Missing: ${verdict.remainingWork.join(', ') || 'none'}, Path: ${verdictPath}`,
      tags: ['reflection', verdict.status, verdict.severity.toLowerCase()],
      relatedCommands: ['forge', 'party', 'verify'],
    });
  }

  await runHooks(verdict);
  return verdict;
}

export function evaluateVerdict(
  verdict: ReflectionVerdict,
  config: ReflectionConfig = DEFAULT_REFLECTION_CONFIG,
): ReflectionEvaluation {
  const missing: string[] = [];

  // Evidence gates
  if (!verdict.evidence.tests.ran) {
    missing.push('Tests were not run');
  } else if (!verdict.evidence.tests.passed) {
    missing.push('Tests did not pass');
  } else if (!verdict.evidence.tests.ranAfterChanges) {
    missing.push('Tests were not re-run after code changes');
  }

  if (!verdict.evidence.build.ran) {
    missing.push('Build was not run');
  } else if (!verdict.evidence.build.passed) {
    missing.push('Build failed');
  }

  if (!verdict.evidence.lint.ran) {
    missing.push('Lint was not run');
  } else if (!verdict.evidence.lint.passed) {
    missing.push('Lint failed');
  }

  // Confidence check
  if (verdict.confidence < config.confidenceThreshold) {
    missing.push(`Confidence ${verdict.confidence} is below threshold ${config.confidenceThreshold}`);
  }

  // Stuck detection
  if (verdict.stuck) {
    missing.push('Agent reported being stuck — rethink approach');
  }

  // Human action check
  if (verdict.needsHumanAction.length > 0) {
    missing.push(`Needs human action: ${verdict.needsHumanAction.join(', ')}`);
  }

  // Remaining work
  for (const item of verdict.remainingWork) {
    missing.push(`Remaining: ${item}`);
  }

  const complete = verdict.status === 'complete' && missing.length === 0;

  // Score: 0–100 based on gates passed
  let score = 0;
  if (verdict.evidence.tests.ran && verdict.evidence.tests.passed) score += 30;
  if (verdict.evidence.build.ran && verdict.evidence.build.passed) score += 25;
  if (verdict.evidence.lint.ran && verdict.evidence.lint.passed) score += 15;
  score += Math.round(verdict.confidence * 20);
  if (verdict.remainingWork.length === 0) score += 10;

  const feedback = complete
    ? 'All evidence gates passed. Task is complete.'
    : `Task incomplete. Missing: ${missing.join('; ')}`;

  return { complete, missing, feedback, score };
}

// Multi-provider LLM client - Grok, Claude, OpenAI, Gemini, Ollama
// Uses direct HTTP calls so package installs work without optional provider SDKs.
//
// Pipeline decomposition (v0.10.0 — Pass 6):
//   callLLM orchestrates 6 stages: enrich → route → budget → dispatch → usage → audit
//   Stages live in llm-pipeline.ts for testability. Provider functions remain here.
import { resolveProvider, loadConfig, type LLMProvider } from './config.js';
import { warnIfExpensive } from './token-estimator.js';
import { logger } from './logger.js';
import { LLMError } from './errors.js';
import {
  enrichPrompt,
  applyRouting,
  enforceBudget,
  dispatchWithRetry,
  handleUsage,
  persistAudit,
  type CallLLMOptions,
  type ProviderResponse,
} from './llm-pipeline.js';

// Re-export types for backward compatibility — definitions moved to llm-pipeline.ts
export type { CallLLMOptions, LLMUsageMetadata, ProviderResponse } from './llm-pipeline.js';
// Re-export error hierarchy for consumers
export { LLMError, BudgetError, DanteError, isRetryableError } from './errors.js';
export type { DanteErrorCode } from './errors.js';

import { MAX_LLM_RETRIES, LLM_RETRY_DELAYS_MS, DEFAULT_LLM_TIMEOUT_MS, DEFAULT_OLLAMA_TIMEOUT_MS } from './llm-config.js';

const MAX_RETRIES = MAX_LLM_RETRIES;
const RETRY_DELAYS_MS = [...LLM_RETRY_DELAYS_MS];
export const DEFAULT_LLM_REQUEST_TIMEOUT_MS = DEFAULT_LLM_TIMEOUT_MS;
export const DEFAULT_OLLAMA_REQUEST_TIMEOUT_MS = DEFAULT_OLLAMA_TIMEOUT_MS;

/** Module-level fetch override — null means use globalThis.fetch at call time (lazy resolution) */
let _llmFetch: typeof globalThis.fetch | null = null;

/** Set a custom fetch function for testing. Affects all LLM provider calls. */
export function setLLMFetch(fn: typeof globalThis.fetch): void { _llmFetch = fn; }

/** Reset the fetch function to use globalThis.fetch (lazy). */
export function resetLLMFetch(): void { _llmFetch = null; }

export interface ProbeResult {
  ok: boolean;
  provider: LLMProvider;
  model: string;
  message: string;
}

export const VERIFIED_LLM_PROVIDER_LABEL = 'verified live LLM provider';
const KNOWN_LLM_PROVIDERS = new Set<LLMProvider>(['grok', 'claude', 'openai', 'gemini', 'ollama']);

function assertKnownProvider(provider: string): void {
  if (KNOWN_LLM_PROVIDERS.has(provider as LLMProvider)) {
    return;
  }

  throw new LLMError(
    `Unknown provider: ${provider}. Use: grok, claude, openai, gemini, ollama`,
    'LLM_UNKNOWN_PROVIDER',
    provider as LLMProvider,
  );
}

// ─── Type Guards ───────────────────────────────────────────────

/** Runtime type guard: value is a non-null object (Record-like) */
function isRecord(v: unknown): v is Record<string, unknown> {
  return typeof v === 'object' && v !== null;
}

/** Safely access a property on an unknown payload — replaces unsafe `as { ... }` casts */
function getField(obj: unknown, key: string): unknown {
  return isRecord(obj) ? obj[key] : undefined;
}

// ─── Helpers ───────────────────────────────────────────────────

function parseTimeoutMs(rawValue: string | undefined, fallbackMs: number): number {
  const value = rawValue?.trim();
  if (!value) return fallbackMs;
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed) || parsed <= 0) return fallbackMs;
  return parsed;
}

export function resolveProviderRequestTimeoutMs(
  provider: LLMProvider,
  env: NodeJS.ProcessEnv = process.env,
): number {
  const baseTimeout = parseTimeoutMs(
    env.DANTEFORGE_LLM_TIMEOUT_MS ?? env.DANTEFORGE_LIVE_TIMEOUT_MS,
    DEFAULT_LLM_REQUEST_TIMEOUT_MS,
  );
  if (provider === 'ollama') {
    return parseTimeoutMs(
      env.OLLAMA_TIMEOUT_MS,
      Math.max(baseTimeout, DEFAULT_OLLAMA_REQUEST_TIMEOUT_MS),
    );
  }
  return baseTimeout;
}

function displayProvider(provider: LLMProvider): string {
  switch (provider) {
    case 'grok': return 'xAI Grok';
    case 'claude': return 'Anthropic Claude';
    case 'openai': return 'OpenAI';
    case 'gemini': return 'Google Gemini';
    case 'ollama': return 'Ollama';
  }
}

function normalizeBaseUrl(provider: LLMProvider, baseUrl?: string): string {
  if (baseUrl) return baseUrl.replace(/\/+$/, '');
  switch (provider) {
    case 'grok': return 'https://api.x.ai/v1';
    case 'openai': return 'https://api.openai.com/v1';
    case 'claude': return 'https://api.anthropic.com';
    case 'gemini': return 'https://generativelanguage.googleapis.com/v1beta';
    case 'ollama': return 'http://127.0.0.1:11434';
  }
}

function requireApiKey(provider: LLMProvider, apiKey: string | undefined): string {
  if (!apiKey) {
    throw new LLMError(
      `No API key configured for ${provider}. Run: danteforge config --set-key "${provider}:<key>"`,
      'CONFIG_MISSING_KEY',
      provider,
    );
  }
  return apiKey;
}

function normalizeProviderError(provider: LLMProvider, status: number, body: string): LLMError {
  const label = displayProvider(provider);
  const snippet = body.replace(/\s+/g, ' ').slice(0, 240).trim();

  if (status === 401 || status === 403) {
    return new LLMError(`${label} authentication failed (${status}). Check your API key and model access.`, 'LLM_AUTH_FAILED', provider, status);
  }
  if (status === 404) {
    return new LLMError(`${label} endpoint or model was not found (404). Check the configured base URL and model.`, 'MODEL_NOT_AVAILABLE', provider, status);
  }
  if (status === 408) {
    return new LLMError(`${label} request timed out (408).`, 'LLM_TIMEOUT', provider, status, true);
  }
  if (status === 429) {
    return new LLMError(`${label} rate limit exceeded (429). Retry later or lower request volume.`, 'LLM_RATE_LIMITED', provider, status, true);
  }
  if (status >= 500) {
    return new LLMError(`${label} is temporarily unavailable (${status}).`, 'LLM_UNAVAILABLE', provider, status, true);
  }
  return new LLMError(`${label} request failed (${status})${snippet ? `: ${snippet}` : ''}`, 'LLM_UNAVAILABLE', provider, status);
}

// ─── Provider JSON Fetching ─────────────────────────────────────

async function fetchProviderJson(
  provider: LLMProvider,
  url: string,
  init: RequestInit,
  timeoutMs = resolveProviderRequestTimeoutMs(provider),
  fetchFn?: typeof globalThis.fetch,
): Promise<unknown> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await (fetchFn ?? _llmFetch ?? globalThis.fetch)(url, {
      ...init,
      signal: controller.signal,
      headers: {
        'content-type': 'application/json',
        ...(init.headers ?? {}),
      },
    });

    const raw = await response.text();
    if (!response.ok) throw normalizeProviderError(provider, response.status, raw);

    if (!raw.trim()) return {};

    try {
      return JSON.parse(raw) as unknown;
    } catch {
      throw new LLMError(`${displayProvider(provider)} returned invalid JSON.`, 'LLM_INVALID_JSON', provider);
    }
  } catch (err) {
    if (err instanceof Error && err.name === 'AbortError') {
      throw new LLMError(`${displayProvider(provider)} request timed out after ${timeoutMs}ms.`, 'LLM_TIMEOUT', provider, undefined, true);
    }
    throw err;
  } finally {
    clearTimeout(timeout);
  }
}

// ─── Response Text Extraction (type-guarded) ─────────────────────

function extractOpenAICompatibleText(payload: unknown): string {
  const choices = getField(payload, 'choices');
  if (!Array.isArray(choices)) return '';
  const message = getField(choices[0], 'message');
  const content = getField(message, 'content');

  if (typeof content === 'string') return content.trim();
  if (Array.isArray(content)) {
    return content.map(part => String(getField(part, 'text') ?? '')).join('').trim();
  }
  return '';
}

function extractClaudeText(payload: unknown): string {
  const content = getField(payload, 'content');
  if (!Array.isArray(content)) return '';
  return content
    .filter(block => getField(block, 'type') === 'text' && typeof getField(block, 'text') === 'string')
    .map(block => getField(block, 'text') as string)
    .join('')
    .trim();
}

function extractGeminiText(payload: unknown): string {
  const candidates = getField(payload, 'candidates');
  if (!Array.isArray(candidates)) return '';
  return candidates
    .flatMap(candidate => {
      const parts = getField(getField(candidate, 'content'), 'parts');
      return Array.isArray(parts) ? parts : [];
    })
    .map(part => String(getField(part, 'text') ?? ''))
    .join('')
    .trim();
}

// ─── Model Resolution ───────────────────────────────────────────

function normalizeModelName(model: string): string {
  return model.trim().toLowerCase().replace(/^models\//, '');
}

function modelMatches(configuredModel: string, candidateModel: string): boolean {
  const configured = normalizeModelName(configuredModel);
  const candidate = normalizeModelName(candidateModel);
  if (configured === candidate) return true;
  const configuredBase = configured.split(':')[0] ?? configured;
  const candidateBase = candidate.split(':')[0] ?? candidate;
  return configuredBase === candidateBase;
}

function dedupeModelNames(models: string[]): string[] {
  const seen = new Set<string>();
  const unique: string[] = [];
  for (const model of models) {
    const normalized = normalizeModelName(model);
    if (seen.has(normalized)) continue;
    seen.add(normalized);
    unique.push(model);
  }
  return unique;
}

function extractProviderModelNames(provider: LLMProvider, payload: unknown): string[] {
  switch (provider) {
    case 'grok':
    case 'openai':
    case 'claude': {
      const data = getField(payload, 'data');
      if (!Array.isArray(data)) return [];
      return data.flatMap(model => {
        const id = getField(model, 'id');
        const name = getField(model, 'name');
        return [id, name].filter((v): v is string => typeof v === 'string');
      });
    }
    case 'gemini': {
      const models = getField(payload, 'models');
      if (!Array.isArray(models)) return [];
      return models.flatMap(model => {
        const name = getField(model, 'name');
        const displayName = getField(model, 'displayName');
        return [name, displayName].filter((v): v is string => typeof v === 'string');
      });
    }
    case 'ollama': {
      const models = getField(payload, 'models');
      if (!Array.isArray(models)) return [];
      return models.flatMap(model => {
        const modelField = getField(model, 'model');
        const name = getField(model, 'name');
        return [modelField, name].filter((v): v is string => typeof v === 'string');
      });
    }
  }
}

function resolveOllamaModelName(configuredModel: string, availableModels: string[]): string {
  const configured = normalizeModelName(configuredModel);
  const exactMatch = availableModels.find(candidate => normalizeModelName(candidate) === configured);
  if (exactMatch) return exactMatch;

  const configuredBase = configured.split(':')[0] ?? configured;
  const baseMatches = availableModels.filter(candidate => {
    const candidateBase = normalizeModelName(candidate).split(':')[0] ?? normalizeModelName(candidate);
    return candidateBase === configuredBase;
  });

  if (baseMatches.length === 1) return baseMatches[0]!;
  if (baseMatches.length > 1) {
    throw new LLMError(
      `Multiple Ollama models match "${configuredModel}": ${baseMatches.join(', ')}. Configure the exact Ollama model tag.`,
      'MODEL_NOT_AVAILABLE',
      'ollama',
    );
  }
  throw new LLMError(
    `Ollama model "${configuredModel}" is not available from the configured endpoint.`,
    'MODEL_NOT_AVAILABLE',
    'ollama',
  );
}

function resolveConfiguredModelName(provider: LLMProvider, configuredModel: string, payload: unknown): string {
  const availableModels = dedupeModelNames(extractProviderModelNames(provider, payload));
  if (availableModels.length === 0) {
    throw new LLMError(
      `${displayProvider(provider)} model listing was reachable, but no models were returned.`,
      'MODEL_NOT_AVAILABLE',
      provider,
    );
  }
  if (provider === 'ollama') return resolveOllamaModelName(configuredModel, availableModels);
  const match = availableModels.find(candidate => modelMatches(configuredModel, candidate));
  if (!match) {
    throw new LLMError(
      `${displayProvider(provider)} model "${configuredModel}" is not available from the configured endpoint.`,
      'MODEL_NOT_AVAILABLE',
      provider,
    );
  }
  return match;
}

async function resolveOllamaCallableModel(configuredModel: string, baseUrl: string, fetchFn?: typeof globalThis.fetch): Promise<string> {
  const payload = await fetchProviderJson('ollama', `${baseUrl}/api/tags`, { method: 'GET' }, undefined, fetchFn);
  return resolveConfiguredModelName('ollama', configuredModel, payload);
}

async function resolveCallTarget(providerOverride?: LLMProvider) {
  const resolved = await resolveProvider();
  const provider = providerOverride ?? resolved.provider;
  const config = await loadConfig();
  const providerConfig = config.providers[provider];
  return {
    provider,
    model: providerConfig?.model ?? resolved.model,
    apiKey: providerConfig?.apiKey ?? resolved.apiKey,
    baseUrl: normalizeBaseUrl(provider, providerConfig?.baseUrl ?? resolved.baseUrl),
    ollamaModel: config.ollamaModel || resolved.model,
  };
}

// ─── Provider Dispatch ──────────────────────────────────────────

async function dispatchToProvider(
  prompt: string,
  target: { provider: LLMProvider; model: string; apiKey: string | undefined; baseUrl: string; ollamaModel: string },
  fetchFn?: typeof globalThis.fetch,
): Promise<{ response: ProviderResponse; modelUsed: string }> {
  switch (target.provider) {
    case 'grok':
    case 'openai':
      return { response: await callOpenAICompatible(prompt, target.provider, target.apiKey, target.model, target.baseUrl, fetchFn), modelUsed: target.model };
    case 'claude':
      return { response: await callClaude(prompt, target.apiKey, target.model, target.baseUrl, fetchFn), modelUsed: target.model };
    case 'gemini':
      return { response: await callGemini(prompt, target.apiKey, target.model, target.baseUrl, fetchFn), modelUsed: target.model };
    case 'ollama': {
      const resolvedModel = await resolveOllamaCallableModel(target.ollamaModel, target.baseUrl, fetchFn);
      return { response: await callOllama(prompt, resolvedModel, target.baseUrl, fetchFn), modelUsed: resolvedModel };
    }
    default:
      throw new LLMError(`Unknown provider: ${target.provider}. Use: grok, claude, openai, gemini, ollama`, 'LLM_UNKNOWN_PROVIDER', target.provider);
  }
}

// ─── Main Entry Point ───────────────────────────────────────────

/**
 * Call the configured LLM provider with automatic retry for transient failures.
 * Orchestrates pipeline stages: enrich → route → budget → dispatch → usage → audit.
 */
export async function callLLM(
  prompt: string,
  providerOverride?: LLMProvider,
  options: CallLLMOptions = {},
): Promise<string> {
  const target = await resolveCallTarget(providerOverride);
  assertKnownProvider(String(target.provider));
  const enriched = await enrichPrompt(prompt, options);
  await applyRouting(options);
  enforceBudget(options);
  await warnIfExpensive(enriched, target.provider);
  logger.info(`LLM call: ${target.provider}/${target.model} (${enriched.length} chars)`);

  const fetchFn = options._fetch;
  const { response, modelUsed, attempt } = await dispatchWithRetry(
    () => dispatchToProvider(enriched, target, fetchFn),
    { maxRetries: MAX_RETRIES, retryDelays: options._retryDelays ?? RETRY_DELAYS_MS },
    target.provider,
    {
      sleep: options._sleep,
      providerDelay: options._retryDelays
        ? (retryAttempt) => options._retryDelays?.[retryAttempt] ?? RETRY_DELAYS_MS[retryAttempt] ?? 1000
        : undefined,
    },
  );

  await handleUsage(response, target.provider, modelUsed, options);
  await persistAudit(response.text, target.provider, modelUsed, enriched.length, attempt, options);
  return response.text;
}

// ─── Probe / Availability ───────────────────────────────────────

/** Check if the configured LLM has a usable live path. */
export async function isLLMAvailable(): Promise<boolean> {
  const probe = await probeLLMProvider();
  return probe.ok;
}

export async function probeLLMProvider(providerOverride?: LLMProvider): Promise<ProbeResult> {
  const target = await resolveCallTarget(providerOverride);

  try {
    switch (target.provider) {
      case 'grok':
      case 'openai': {
        const key = requireApiKey(target.provider, target.apiKey);
        const payload = await fetchProviderJson(target.provider, `${target.baseUrl}/models`, {
          method: 'GET',
          headers: { Authorization: `Bearer ${key}` },
        });
        const resolvedModel = resolveConfiguredModelName(target.provider, target.model, payload);
        return { ok: true, provider: target.provider, model: resolvedModel, message: `${displayProvider(target.provider)} model "${resolvedModel}" is reachable.` };
      }
      case 'claude': {
        const key = requireApiKey('claude', target.apiKey);
        const payload = await fetchProviderJson('claude', `${target.baseUrl}/v1/models`, {
          method: 'GET',
          headers: { 'x-api-key': key, 'anthropic-version': '2023-06-01' },
        });
        const resolvedModel = resolveConfiguredModelName('claude', target.model, payload);
        return { ok: true, provider: 'claude', model: resolvedModel, message: `Anthropic Claude model "${resolvedModel}" is reachable.` };
      }
      case 'gemini': {
        const key = requireApiKey('gemini', target.apiKey);
        const payload = await fetchProviderJson('gemini', `${target.baseUrl}/models?key=${encodeURIComponent(key)}`, { method: 'GET' });
        const resolvedModel = resolveConfiguredModelName('gemini', target.model, payload);
        return { ok: true, provider: 'gemini', model: resolvedModel, message: `Google Gemini model "${resolvedModel}" is reachable.` };
      }
      case 'ollama': {
        const resolvedModel = await resolveOllamaCallableModel(target.ollamaModel, target.baseUrl);
        const resolutionMessage = resolvedModel === target.ollamaModel
          ? `Ollama model "${resolvedModel}" is reachable.`
          : `Ollama model "${target.ollamaModel}" resolved to "${resolvedModel}" and is reachable.`;
        return { ok: true, provider: 'ollama', model: resolvedModel, message: resolutionMessage };
      }
    }
  } catch (err) {
    return { ok: false, provider: target.provider, model: target.model, message: err instanceof Error ? err.message : String(err) };
  }
}

// ─── Provider Functions ─────────────────────────────────────────

async function callOpenAICompatible(
  prompt: string,
  provider: 'grok' | 'openai',
  apiKey: string | undefined,
  model: string,
  baseUrl: string,
  fetchFn?: typeof globalThis.fetch,
): Promise<ProviderResponse> {
  const key = requireApiKey(provider, apiKey);
  const payload = await fetchProviderJson(provider, `${baseUrl}/chat/completions`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${key}` },
    body: JSON.stringify({ model, messages: [{ role: 'user', content: prompt }], max_tokens: 4096 }),
  }, undefined, fetchFn);

  const text = extractOpenAICompatibleText(payload);
  if (!text) throw new LLMError(`${displayProvider(provider)} returned an empty response.`, 'LLM_EMPTY_RESPONSE', provider);
  return { text, usage: extractOpenAIUsage(payload) };
}

async function callClaude(
  prompt: string,
  apiKey: string | undefined,
  model: string,
  baseUrl: string,
  fetchFn?: typeof globalThis.fetch,
): Promise<ProviderResponse> {
  const key = requireApiKey('claude', apiKey);
  const payload = await fetchProviderJson('claude', `${baseUrl}/v1/messages`, {
    method: 'POST',
    headers: { 'x-api-key': key, 'anthropic-version': '2023-06-01' },
    body: JSON.stringify({ model, max_tokens: 4096, messages: [{ role: 'user', content: prompt }] }),
  }, undefined, fetchFn);

  const text = extractClaudeText(payload);
  if (!text) throw new LLMError('Anthropic Claude returned an empty response.', 'LLM_EMPTY_RESPONSE', 'claude');
  return { text, usage: extractClaudeUsage(payload) };
}

async function callGemini(
  prompt: string,
  apiKey: string | undefined,
  model: string,
  baseUrl: string,
  fetchFn?: typeof globalThis.fetch,
): Promise<ProviderResponse> {
  const key = requireApiKey('gemini', apiKey);
  const payload = await fetchProviderJson(
    'gemini',
    `${baseUrl}/models/${encodeURIComponent(model)}:generateContent?key=${encodeURIComponent(key)}`,
    {
      method: 'POST',
      body: JSON.stringify({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        generationConfig: { maxOutputTokens: 4096 },
      }),
    },
    undefined,
    fetchFn,
  );

  const text = extractGeminiText(payload);
  if (!text) throw new LLMError('Google Gemini returned an empty response.', 'LLM_EMPTY_RESPONSE', 'gemini');
  return { text, usage: extractGeminiUsage(payload) };
}

async function callOllama(prompt: string, model: string, baseUrl: string, fetchFn?: typeof globalThis.fetch): Promise<ProviderResponse> {
  const payload = await fetchProviderJson('ollama', `${baseUrl}/api/chat`, {
    method: 'POST',
    body: JSON.stringify({ model, stream: false, messages: [{ role: 'user', content: prompt }] }),
  }, undefined, fetchFn);

  const message = getField(payload, 'message');
  const content = isRecord(message) ? String(message.content ?? '').trim() : '';
  if (!content) throw new LLMError('Ollama returned an empty response.', 'LLM_EMPTY_RESPONSE', 'ollama');
  return { text: content, usage: extractOllamaUsage(payload) };
}

// ─── Usage Extraction (type-guarded) ─────────────────────────────

/** Extract token usage from an OpenAI-compatible response payload */
export function extractOpenAIUsage(payload: unknown): { inputTokens: number; outputTokens: number } | undefined {
  const usage = getField(payload, 'usage');
  if (!isRecord(usage)) return undefined;
  const input = Number(usage.prompt_tokens ?? 0);
  const output = Number(usage.completion_tokens ?? 0);
  return (input > 0 || output > 0) ? { inputTokens: input, outputTokens: output } : undefined;
}

/** Extract token usage from a Claude/Anthropic response payload */
export function extractClaudeUsage(payload: unknown): { inputTokens: number; outputTokens: number } | undefined {
  const usage = getField(payload, 'usage');
  if (!isRecord(usage)) return undefined;
  const input = Number(usage.input_tokens ?? 0);
  const output = Number(usage.output_tokens ?? 0);
  return (input > 0 || output > 0) ? { inputTokens: input, outputTokens: output } : undefined;
}

/** Extract token usage from a Gemini response payload */
export function extractGeminiUsage(payload: unknown): { inputTokens: number; outputTokens: number } | undefined {
  const meta = getField(payload, 'usageMetadata');
  if (!isRecord(meta)) return undefined;
  const input = Number(meta.promptTokenCount ?? 0);
  const output = Number(meta.candidatesTokenCount ?? 0);
  return (input > 0 || output > 0) ? { inputTokens: input, outputTokens: output } : undefined;
}

/** Extract token usage from an Ollama response payload */
export function extractOllamaUsage(payload: unknown): { inputTokens: number; outputTokens: number } | undefined {
  if (!isRecord(payload)) return undefined;
  const input = Number(payload.prompt_eval_count ?? 0);
  const output = Number(payload.eval_count ?? 0);
  return (input > 0 || output > 0) ? { inputTokens: input, outputTokens: output } : undefined;
}

// Secure config management: API keys stored in a user-level .danteforge/config.yaml
import fs from 'fs/promises';
import os from 'os';
import path from 'path';
import yaml from 'yaml';
import { logger } from './logger.js';

const CONFIG_DIRNAME = '.danteforge';
const CONFIG_FILENAME = 'config.yaml';

export type LLMProvider = 'grok' | 'claude' | 'openai' | 'gemini' | 'ollama';

export interface DanteConfig {
  defaultProvider: LLMProvider;
  ollamaModel: string;
  providers: Partial<Record<LLMProvider, { apiKey?: string; model?: string; baseUrl?: string }>>;
  figma?: {
    defaultFileUrl?: string;
    designTokensPath?: string;
    mcpServerName?: string;
  };
}

export interface ConfigPathOptions {
  cwd?: string;
  homeDir?: string;
  env?: NodeJS.ProcessEnv;
}

export interface ConfigPaths {
  configDir: string;
  configFile: string;
  legacyProjectConfigFile: string;
}

const DEFAULT_CONFIG: DanteConfig = {
  defaultProvider: 'ollama',
  ollamaModel: 'llama3',
  providers: {},
};

// Default models per provider
const DEFAULT_MODELS: Record<LLMProvider, string> = {
  grok: 'grok-3-mini',
  claude: 'claude-sonnet-4-20250514',
  openai: 'gpt-4o',
  gemini: 'gemini-2.0-flash',
  ollama: 'llama3',
};

// Default base URLs per provider
const DEFAULT_BASE_URLS: Record<string, string> = {
  grok: 'https://api.x.ai/v1',
  openai: 'https://api.openai.com/v1',
  claude: 'https://api.anthropic.com',
  gemini: 'https://generativelanguage.googleapis.com/v1beta',
  ollama: 'http://127.0.0.1:11434',
};

export function getDefaultModel(provider: LLMProvider): string {
  return DEFAULT_MODELS[provider];
}

export function getDefaultBaseUrl(provider: LLMProvider): string | undefined {
  return DEFAULT_BASE_URLS[provider];
}

function mergeWithDefaults(parsed?: Partial<DanteConfig> | null): DanteConfig {
  // Deep merge providers to preserve existing keys when config is partial
  const mergedProviders: DanteConfig['providers'] = { ...DEFAULT_CONFIG.providers };
  if (parsed?.providers) {
    for (const [key, value] of Object.entries(parsed.providers)) {
      mergedProviders[key as LLMProvider] = { ...mergedProviders[key as LLMProvider], ...value };
    }
  }
  return {
    ...DEFAULT_CONFIG,
    ...parsed,
    providers: mergedProviders,
  };
}

export function resolveConfigPaths(options: ConfigPathOptions = {}): ConfigPaths {
  const cwd = options.cwd ?? process.cwd();
  const env = options.env ?? process.env;
  const homeDir = options.homeDir ?? env.DANTEFORGE_HOME ?? env.HOME ?? env.USERPROFILE ?? os.homedir();
  const configDir = path.join(homeDir, CONFIG_DIRNAME);

  return {
    configDir,
    configFile: path.join(configDir, CONFIG_FILENAME),
    legacyProjectConfigFile: path.join(cwd, CONFIG_DIRNAME, CONFIG_FILENAME),
  };
}

async function readConfigFile(filePath: string): Promise<DanteConfig> {
  const content = await fs.readFile(filePath, 'utf8');
  const parsed = yaml.parse(content) as Partial<DanteConfig>;
  return mergeWithDefaults(parsed);
}

export async function loadConfig(options: ConfigPathOptions = {}): Promise<DanteConfig> {
  const paths = resolveConfigPaths(options);

  try {
    return await readConfigFile(paths.configFile);
  } catch {
    try {
      const legacyConfig = await readConfigFile(paths.legacyProjectConfigFile);
      await saveConfig(legacyConfig, options);
      logger.warn(`Migrated config from ${paths.legacyProjectConfigFile} to ${paths.configFile}`);
      return legacyConfig;
    } catch {
      return mergeWithDefaults();
    }
  }
}

export async function saveConfig(config: DanteConfig, options: ConfigPathOptions = {}): Promise<void> {
  const paths = resolveConfigPaths(options);
  await fs.mkdir(paths.configDir, { recursive: true });
  await fs.writeFile(paths.configFile, yaml.stringify(config), { mode: 0o600 });

  if (process.platform !== 'win32') {
    try {
      await fs.chmod(paths.configFile, 0o600);
    } catch {
      // Ignore chmod failures on filesystems without POSIX mode support.
    }
  }
}

export async function setApiKey(provider: LLMProvider, apiKey: string): Promise<void> {
  const config = await loadConfig();
  if (!config.providers[provider]) {
    config.providers[provider] = {};
  }
  config.providers[provider]!.apiKey = apiKey;

  // Auto-set as default provider when first key is added
  if (config.defaultProvider === 'ollama' && provider !== 'ollama') {
    config.defaultProvider = provider;
    logger.info(`Default provider set to ${provider}`);
  }

  await saveConfig(config);
  logger.success(`API key saved for ${provider}`);
}

export async function getApiKey(provider: LLMProvider): Promise<string | undefined> {
  const config = await loadConfig();
  return config.providers[provider]?.apiKey;
}

export async function deleteApiKey(provider: LLMProvider): Promise<void> {
  const config = await loadConfig();
  if (config.providers[provider]) {
    delete config.providers[provider]!.apiKey;
  }
  await saveConfig(config);
  logger.success(`API key removed for ${provider}`);
}

export async function setDefaultProvider(provider: LLMProvider): Promise<void> {
  const config = await loadConfig();
  config.defaultProvider = provider;
  await saveConfig(config);
  logger.success(`Default provider set to ${provider}`);
}

export async function setProviderModel(provider: LLMProvider, model: string): Promise<void> {
  const config = await loadConfig();
  if (!config.providers[provider]) {
    config.providers[provider] = {};
  }
  config.providers[provider]!.model = model;
  await saveConfig(config);
  logger.success(`Model for ${provider} set to ${model}`);
}

/**
 * Check if any API key is configured (not counting ollama)
 */
export async function hasApiKey(): Promise<boolean> {
  const config = await loadConfig();
  return Object.entries(config.providers).some(
    ([provider, settings]) => provider !== 'ollama' && settings?.apiKey,
  );
}

/**
 * Get the resolved provider + model + key for the current config
 */
export async function resolveProvider(): Promise<{
  provider: LLMProvider;
  model: string;
  apiKey?: string;
  baseUrl?: string;
}> {
  const config = await loadConfig();
  const provider = config.defaultProvider;
  const providerConfig = config.providers[provider];

  return {
    provider,
    model: providerConfig?.model ?? DEFAULT_MODELS[provider],
    apiKey: providerConfig?.apiKey,
    baseUrl: providerConfig?.baseUrl ?? DEFAULT_BASE_URLS[provider],
  };
}

// Token estimation, cost warnings, and auto-chunking for LLM API calls
import { logger } from './logger.js';
import type { LLMProvider } from './config.js';

/**
 * Approximate context window limits per provider (in tokens).
 * These reflect the default models configured in config.ts.
 */
export const TOKEN_LIMITS: Record<LLMProvider, number> = {
  grok: 131072,    // grok-3-mini
  claude: 200000,  // claude-sonnet-4
  openai: 128000,  // gpt-4o
  gemini: 1048576, // gemini-2.0-flash
  ollama: 8192,    // llama3 default context
};

/**
 * Rough per-token pricing in USD (input / output per 1M tokens).
 * These are ballpark figures for user awareness, not billing-accurate.
 */
const PRICING: Record<LLMProvider, { inputPer1M: number; outputPer1M: number }> = {
  grok: { inputPer1M: 5.00, outputPer1M: 15.00 },
  claude: { inputPer1M: 3.00, outputPer1M: 15.00 },
  openai: { inputPer1M: 2.50, outputPer1M: 10.00 },
  gemini: { inputPer1M: 0.10, outputPer1M: 0.40 },
  ollama: { inputPer1M: 0, outputPer1M: 0 },  // local, free
};

/**
 * Token estimation strategy.
 * - 'simple': ~4 chars/token (conservative, backward-compatible default)
 * - 'code-aware': ~2.5 chars/token for code, ~3.5 for prose (more accurate)
 */
export type TokenEstimationStrategy = 'simple' | 'code-aware';

/**
 * Heuristic: detect whether text is likely code or prose.
 * Code has a higher density of special characters ({, }, ;, =, <, >, etc.).
 */
export function isLikelyCode(text: string): boolean {
  if (text.length === 0) return false;
  const codeSignals = (text.match(/[{}();=<>[\]|&!~^+\-*/%]/g) || []).length;
  return (codeSignals / text.length) > 0.02;
}

/**
 * Estimate token count for a given text.
 * @param text The input text to estimate tokens for.
 * @param strategy Estimation strategy — 'simple' (4:1) or 'code-aware' (variable ratio).
 */
export function estimateTokens(text: string, strategy: TokenEstimationStrategy = 'simple'): number {
  if (strategy === 'simple') return Math.ceil(text.length / 4);
  const ratio = isLikelyCode(text) ? 2.5 : 3.5;
  return Math.ceil(text.length / ratio);
}

/**
 * Estimate the cost of a prompt based on token count and provider pricing.
 * Assumes output will be roughly 25% of input length (conservative guess).
 */
export function estimateCost(
  tokens: number,
  provider: LLMProvider
): { inputCost: number; outputCost: number; totalEstimate: number } {
  const pricing = PRICING[provider];
  const inputCost = (tokens / 1_000_000) * pricing.inputPer1M;
  // Assume output is ~25% of input tokens for cost estimation
  const estimatedOutputTokens = Math.ceil(tokens * 0.25);
  const outputCost = (estimatedOutputTokens / 1_000_000) * pricing.outputPer1M;
  const totalEstimate = inputCost + outputCost;

  return {
    inputCost: Math.round(inputCost * 1_000_000) / 1_000_000,
    outputCost: Math.round(outputCost * 1_000_000) / 1_000_000,
    totalEstimate: Math.round(totalEstimate * 1_000_000) / 1_000_000,
  };
}

/**
 * Warn the user if estimated cost exceeds $0.01.
 * In non-interactive CLI mode we always proceed, but still log the warning.
 * Returns true if the call should proceed.
 */
export async function warnIfExpensive(
  text: string,
  provider: LLMProvider
): Promise<boolean> {
  const tokens = estimateTokens(text);
  const cost = estimateCost(tokens, provider);

  if (cost.totalEstimate > 0.01) {
    logger.warn(
      `Estimated cost for this call: ~$${cost.totalEstimate.toFixed(4)} ` +
      `(${tokens.toLocaleString()} tokens, ${provider}) — ` +
      `input: $${cost.inputCost.toFixed(4)}, output: $${cost.outputCost.toFixed(4)}`
    );
  }

  const limit = TOKEN_LIMITS[provider];
  if (tokens > limit) {
    logger.warn(
      `Input (~${tokens.toLocaleString()} tokens) exceeds ${provider} context limit ` +
      `(${limit.toLocaleString()} tokens). Consider chunking the input.`
    );
  }

  // Non-interactive CLI: always proceed
  return true;
}

/**
 * Split text into chunks that fit within a token limit.
 * Tries to split at paragraph boundaries (double newlines) first,
 * then falls back to single newlines, then hard-splits at the limit.
 */
export function chunkText(text: string, maxTokens: number = 100_000): string[] {
  const maxChars = maxTokens * 4; // inverse of estimateTokens

  if (text.length <= maxChars) {
    return [text];
  }

  const chunks: string[] = [];
  let remaining = text;

  while (remaining.length > 0) {
    if (remaining.length <= maxChars) {
      chunks.push(remaining);
      break;
    }

    // Try to find a paragraph boundary (double newline) within the limit
    let splitIndex = remaining.lastIndexOf('\n\n', maxChars);

    // If no paragraph boundary, try a single newline
    if (splitIndex <= 0) {
      splitIndex = remaining.lastIndexOf('\n', maxChars);
    }

    // If no newline at all, hard-split at the character limit
    if (splitIndex <= 0) {
      splitIndex = maxChars;
    }

    chunks.push(remaining.slice(0, splitIndex));
    remaining = remaining.slice(splitIndex).replace(/^\n+/, ''); // trim leading newlines from next chunk
  }

  if (chunks.length > 1) {
    logger.info(`Text split into ${chunks.length} chunks (max ${maxTokens.toLocaleString()} tokens each)`);
  }

  return chunks;
}

// Structured error hierarchy for DanteForge
import type { LLMProvider } from './config.js';

export type DanteErrorCode =
  | 'LLM_AUTH_FAILED'
  | 'LLM_TIMEOUT'
  | 'LLM_UNAVAILABLE'
  | 'LLM_EMPTY_RESPONSE'
  | 'LLM_INVALID_JSON'
  | 'LLM_UNKNOWN_PROVIDER'
  | 'LLM_RATE_LIMITED'
  | 'LLM_CIRCUIT_OPEN'
  | 'BUDGET_EXCEEDED'
  | 'MODEL_NOT_AVAILABLE'
  | 'CONFIG_MISSING_KEY';

export class DanteError extends Error {
  constructor(
    message: string,
    public readonly code: DanteErrorCode,
    public readonly retryable = false,
  ) {
    super(message);
    this.name = 'DanteError';
  }
}

export class LLMError extends DanteError {
  constructor(
    message: string,
    code: DanteErrorCode,
    public readonly provider: LLMProvider,
    public readonly status?: number,
    retryable = false,
  ) {
    super(message, code, retryable);
    this.name = 'LLMError';
  }
}

export class BudgetError extends DanteError {
  constructor(
    message: string,
    public readonly agentRole: string,
    public readonly currentSpendUsd: number,
    public readonly maxBudgetUsd: number,
  ) {
    super(message, 'BUDGET_EXCEEDED', false);
    this.name = 'BudgetError';
  }
}

/** Check whether an error is retryable — supports DanteError.retryable and string pattern matching */
export function isRetryableError(err: unknown): boolean {
  if (err instanceof DanteError) return err.retryable;
  if (!(err instanceof Error)) return false;
  const msg = err.message.toLowerCase();
  return msg.includes('econnreset')
    || msg.includes('econnrefused')
    || msg.includes('etimedout')
    || msg.includes('socket hang up')
    || msg.includes('fetch failed')
    || msg.includes('rate limit')
    || msg.includes('429')
    || msg.includes('503')
    || msg.includes('502');
}

// LLM pipeline stages — extracted from callLLM for testability and single-responsibility
import { checkContextRot, truncateContext } from '../harvested/gsd/hooks/context-rot.js';
import { injectContext } from './context-injector.js';
import { logger } from './logger.js';
import { recordMemory } from './memory-engine.js';
import { BudgetError, LLMError, isRetryableError } from './errors.js';
import { shouldAllowRequest, recordSuccess, recordFailure, computeBackoffDelay } from './circuit-breaker.js';
import { cachedLoadState, cachedSaveState } from './state-cache.js';
import type { LLMProvider } from './config.js';

export interface CallLLMOptions {
  enrichContext?: boolean;
  recordMemory?: boolean;
  cwd?: string;
  /** Task signature for routing decisions (v0.9.0 — 3-tier model routing) */
  taskSignature?: import('./task-router.js').TaskSignature;
  /** Budget fence for per-agent cost caps (v0.9.0 — budget fences) */
  budgetFence?: { agentRole: string; maxBudgetUsd: number; currentSpendUsd: number; isExceeded: boolean; warningThresholdPercent: number };
  /** Callback for real token usage data from provider responses (v0.9.0 hardening) */
  onUsage?: (usage: LLMUsageMetadata) => void;
  /** Injected fetch function for testing — replaces globalThis.fetch in all provider calls */
  _fetch?: typeof globalThis.fetch;
  /** Injected sleep function for retry-path tests — avoids real backoff waits */
  _sleep?: (ms: number) => Promise<void>;
  /** Injected retry delays for tests — overrides the default/provider backoff sequence */
  _retryDelays?: number[];
}

/** Real token usage metadata extracted from LLM provider responses */
export interface LLMUsageMetadata {
  inputTokens: number;
  outputTokens: number;
  costUsd: number;
  model: string;
  provider: LLMProvider;
}

/** Internal type for provider call results — text + optional usage data */
export interface ProviderResponse {
  text: string;
  usage?: { inputTokens: number; outputTokens: number };
}

/** Result from dispatchWithRetry — includes the attempt index for audit logging */
export interface DispatchResult {
  response: ProviderResponse;
  modelUsed: string;
  attempt: number;
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/** Stage 1: Enrich prompt with context injection + apply context rot truncation */
export async function enrichPrompt(prompt: string, options: Pick<CallLLMOptions, 'enrichContext' | 'cwd'>): Promise<string> {
  let enriched = options.enrichContext
    ? await injectContext(prompt, undefined, options.cwd)
    : prompt;

  const rotResult = checkContextRot(enriched.length);
  if (rotResult.shouldTruncate && rotResult.truncateTarget) {
    enriched = truncateContext(enriched, rotResult.truncateTarget);
  }
  return enriched;
}

/** Stage 2: Check task routing (3-tier) — informational only, best-effort */
export async function applyRouting(options: Pick<CallLLMOptions, 'taskSignature'>): Promise<void> {
  if (!options.taskSignature) return;
  try {
    const { routeTask } = await import('./task-router.js');
    const decision = routeTask(options.taskSignature);
    if (decision.tier === 'local') {
      logger.info(`[Router] Task routed to local tier: ${decision.reason}`);
    }
  } catch (err) {
    logger.verbose(`[best-effort] routing: ${err instanceof Error ? err.message : String(err)}`);
  }
}

/** Stage 3: Enforce budget fence — throws BudgetError when exceeded, warns near threshold */
export function enforceBudget(options: Pick<CallLLMOptions, 'budgetFence'>): void {
  if (!options.budgetFence) return;
  const fence = options.budgetFence;
  if (fence.currentSpendUsd >= fence.maxBudgetUsd) {
    throw new BudgetError(
      `Budget fence exceeded for ${fence.agentRole}: $${fence.currentSpendUsd.toFixed(4)} of $${fence.maxBudgetUsd.toFixed(4)} max`,
      fence.agentRole,
      fence.currentSpendUsd,
      fence.maxBudgetUsd,
    );
  }
  const usagePercent = (fence.currentSpendUsd / fence.maxBudgetUsd) * 100;
  if (usagePercent >= fence.warningThresholdPercent) {
    logger.warn(`[Budget] ${fence.agentRole} at ${usagePercent.toFixed(0)}% of budget ($${fence.currentSpendUsd.toFixed(4)}/$${fence.maxBudgetUsd.toFixed(4)})`);
  }
}

/** Stage 4: Dispatch with retry + backoff — accepts a dispatcher callback for provider isolation.
 *  When `provider` is given, circuit breaker protects the call and exponential backoff is used. */
export async function dispatchWithRetry(
  dispatcher: () => Promise<{ response: ProviderResponse; modelUsed: string }>,
  config: { maxRetries: number; retryDelays: number[] },
  provider?: string,
  hooks?: {
    sleep?: (ms: number) => Promise<void>;
    providerDelay?: (attempt: number) => number;
  },
): Promise<DispatchResult> {
  let lastError: unknown;
  for (let attempt = 0; attempt <= config.maxRetries; attempt++) {
    // Circuit breaker gate — reject immediately if provider circuit is open
    if (provider && !shouldAllowRequest(provider)) {
      throw new LLMError(
        `Circuit breaker OPEN for provider '${provider}' — too many consecutive failures`,
        'LLM_CIRCUIT_OPEN',
        provider as LLMProvider,
        undefined,
        false,
      );
    }
    try {
      const result = await dispatcher();
      if (provider) recordSuccess(provider);
      return { ...result, attempt };
    } catch (err) {
      if (provider) recordFailure(provider);
      lastError = err;
      if (attempt < config.maxRetries && isRetryableError(err)) {
        const delay = provider
          ? (hooks?.providerDelay?.(attempt) ?? computeBackoffDelay(attempt))
          : (config.retryDelays[attempt] ?? 1000);
        logger.warn(`LLM call failed (attempt ${attempt + 1}/${config.maxRetries + 1}): ${err instanceof Error ? err.message : String(err)} - retrying in ${delay}ms`);
        await (hooks?.sleep ?? sleep)(delay);
        continue;
      }
      throw err;
    }
  }
  throw lastError;
}

/** Stage 5: Record usage + update budget fence after successful dispatch */
export async function handleUsage(
  response: ProviderResponse,
  provider: LLMProvider,
  model: string,
  options: Pick<CallLLMOptions, 'onUsage' | 'budgetFence'>,
): Promise<LLMUsageMetadata | undefined> {
  if (!response.usage) return undefined;

  const { estimateCost } = await import('./token-estimator.js');
  const totalTokens = response.usage.inputTokens + response.usage.outputTokens;
  const costData = estimateCost(totalTokens, provider);
  const metadata: LLMUsageMetadata = {
    inputTokens: response.usage.inputTokens,
    outputTokens: response.usage.outputTokens,
    costUsd: costData.totalEstimate,
    model,
    provider,
  };
  try { options.onUsage?.(metadata); } catch (err) {
    logger.verbose(`[best-effort] onUsage callback: ${err instanceof Error ? err.message : String(err)}`);
  }
  if (options.budgetFence) {
    options.budgetFence.currentSpendUsd += costData.totalEstimate;
    if (options.budgetFence.currentSpendUsd >= options.budgetFence.maxBudgetUsd) {
      options.budgetFence.isExceeded = true;
    }
  }
  return metadata;
}

/** Stage 6: Persist audit log + memory entry */
export async function persistAudit(
  output: string,
  provider: LLMProvider,
  model: string,
  enrichedPromptLength: number,
  attempt: number,
  options: Pick<CallLLMOptions, 'recordMemory' | 'cwd'>,
): Promise<void> {
  const state = await cachedLoadState({ cwd: options.cwd });
  state.auditLog.push(`${new Date().toISOString()} | llm: ${provider}/${model} (${output.length} chars returned${attempt > 0 ? `, attempt ${attempt + 1}` : ''})`);
  await cachedSaveState(state, { cwd: options.cwd });

  if (options.recordMemory !== false) {
    await recordMemory({
      category: 'command',
      summary: `LLM call: ${provider}/${model}`,
      detail: `Prompt chars: ${enrichedPromptLength}. Response chars: ${output.length}.`,
      tags: ['llm', provider, model],
      relatedCommands: ['llm'],
    }, options.cwd);
  }
}

// Context rot detection — warns and mitigates when LLM context is getting too large
import { logger } from '../../../core/logger.js';

export const CONTEXT_WARN_THRESHOLD = 120_000;
export const CONTEXT_CRITICAL_THRESHOLD = 180_000;
export const CONTEXT_TRUNCATE_TARGET = 100_000;

export interface ContextRotResult {
  level: 'ok' | 'warning' | 'critical';
  contextSize: number;
  recommendation: string;
  shouldTruncate: boolean;
  truncateTarget?: number;
}

export function checkContextRot(currentContextSize: number): ContextRotResult {
  if (currentContextSize > CONTEXT_CRITICAL_THRESHOLD) {
    logger.warn('CONTEXT ROT DETECTED — auto-truncating before next LLM call');
    return {
      level: 'critical',
      contextSize: currentContextSize,
      recommendation: 'Fresh context recommended — auto-truncating to preserve signal',
      shouldTruncate: true,
      truncateTarget: CONTEXT_TRUNCATE_TARGET,
    };
  }
  if (currentContextSize > CONTEXT_WARN_THRESHOLD) {
    logger.warn('Context getting large — consider wrapping up current wave');
    return {
      level: 'warning',
      contextSize: currentContextSize,
      recommendation: 'Consider wrapping up current wave to avoid context degradation',
      shouldTruncate: false,
    };
  }
  return {
    level: 'ok',
    contextSize: currentContextSize,
    recommendation: 'Context size is healthy',
    shouldTruncate: false,
  };
}

export function truncateContext(content: string, targetChars: number): string {
  if (content.length <= targetChars) return content;

  const keepStart = Math.floor(targetChars * 0.2);
  const keepEnd = targetChars - keepStart;
  const marker = '\n\n[...context truncated to preserve recent signal...]\n\n';

  return content.slice(0, keepStart) + marker + content.slice(content.length - keepEnd);
}

// Context Injection Layer — memory-aware progressive context injection
import { searchMemory, getRecentMemory, getMemoryBudget } from './memory-engine.js';
import { estimateTokens } from './token-estimator.js';
import { logger } from './logger.js';
import type { MemoryEntry } from './memory-store.js';
import fs from 'fs/promises';

const DEFAULT_MAX_BUDGET = 4000; // tokens for injected context
const LESSONS_FILE = '.danteforge/lessons.md';

interface ContextTier {
  label: string;
  entries: string[];
  tokens: number;
}

/**
 * Extract key terms from a prompt for memory search.
 */
function extractKeyTerms(prompt: string): string[] {
  const stopWords = new Set([
    'the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'being',
    'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'could',
    'should', 'may', 'might', 'shall', 'can', 'need', 'must', 'to', 'of',
    'in', 'for', 'on', 'with', 'at', 'by', 'from', 'as', 'into', 'through',
    'and', 'or', 'but', 'not', 'no', 'if', 'then', 'else', 'when', 'up',
    'out', 'so', 'than', 'too', 'very', 'just', 'about', 'also', 'that',
    'this', 'these', 'those', 'it', 'its', 'you', 'your', 'we', 'our',
  ]);

  return prompt
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 2 && !stopWords.has(w))
    .slice(0, 10);
}

/**
 * Load lessons from .danteforge/lessons.md if it exists.
 */
async function loadLessons(cwd?: string): Promise<string> {
  try {
    const filePath = cwd ? `${cwd}/${LESSONS_FILE}` : LESSONS_FILE;
    return await fs.readFile(filePath, 'utf8');
  } catch {
    return '';
  }
}

/**
 * Format a memory entry for injection.
 */
function formatEntry(entry: MemoryEntry): string {
  const prefix = entry.category === 'correction' ? '[CORRECTION]'
    : entry.category === 'error' ? '[ERROR]'
    : entry.category === 'decision' ? '[DECISION]'
    : entry.category === 'insight' ? '[INSIGHT]'
    : '[NOTE]';
  return `${prefix} ${entry.summary}`;
}

/**
 * Build progressive context tiers within a token budget.
 * Tier 1 (always): Error corrections and critical lessons
 * Tier 2 (if budget): Recent decisions and insights
 * Tier 3 (if budget): Historical command summaries
 */
export function buildProgressiveContext(
  memories: MemoryEntry[],
  lessons: string,
  budget: number,
): string {
  const tiers: ContextTier[] = [
    { label: 'Critical Corrections', entries: [], tokens: 0 },
    { label: 'Recent Decisions', entries: [], tokens: 0 },
    { label: 'Historical Context', entries: [], tokens: 0 },
  ];

  // Tier 1: Corrections and errors (highest priority)
  for (const m of memories) {
    if (m.category === 'correction' || m.category === 'error') {
      const formatted = formatEntry(m);
      tiers[0].entries.push(formatted);
      tiers[0].tokens += estimateTokens(formatted);
    }
  }

  // Add lessons to tier 1 if available
  if (lessons.length > 0) {
    const lessonLines = lessons.split('\n').filter(l => l.trim().startsWith('-')).slice(0, 10);
    for (const line of lessonLines) {
      tiers[0].entries.push(`[LESSON] ${line.trim().slice(2)}`);
      tiers[0].tokens += estimateTokens(line);
    }
  }

  // Tier 2: Recent decisions and insights
  for (const m of memories) {
    if (m.category === 'decision' || m.category === 'insight') {
      const formatted = formatEntry(m);
      tiers[1].entries.push(formatted);
      tiers[1].tokens += estimateTokens(formatted);
    }
  }

  // Tier 3: Command summaries
  for (const m of memories) {
    if (m.category === 'command') {
      const formatted = formatEntry(m);
      tiers[2].entries.push(formatted);
      tiers[2].tokens += estimateTokens(formatted);
    }
  }

  // Progressively include tiers within budget
  const parts: string[] = [];
  let remainingBudget = budget;

  for (const tier of tiers) {
    if (tier.entries.length === 0) continue;
    if (remainingBudget <= 0) break;

    const tierText = tier.entries.join('\n');
    const tierTokens = estimateTokens(tierText);

    if (tierTokens <= remainingBudget) {
      parts.push(`### ${tier.label}\n${tierText}`);
      remainingBudget -= tierTokens;
    } else {
      // Partial inclusion: take what fits
      const partialEntries: string[] = [];
      for (const entry of tier.entries) {
        const entryTokens = estimateTokens(entry);
        if (entryTokens <= remainingBudget) {
          partialEntries.push(entry);
          remainingBudget -= entryTokens;
        } else {
          break;
        }
      }
      if (partialEntries.length > 0) {
        parts.push(`### ${tier.label}\n${partialEntries.join('\n')}`);
      }
    }
  }

  return parts.join('\n\n');
}

/**
 * Main entry point: inject relevant past context into a prompt.
 * Returns the enriched prompt with a "Prior Context" section appended.
 */
export async function injectContext(
  prompt: string,
  maxTokenBudget: number = DEFAULT_MAX_BUDGET,
  cwd?: string,
): Promise<string> {
  const budget = await getMemoryBudget(cwd);
  if (budget.entryCount === 0) {
    // No memory — return prompt as-is
    return prompt;
  }

  const promptTokens = estimateTokens(prompt);
  const availableBudget = Math.max(0, maxTokenBudget - Math.min(promptTokens * 0.1, 500));

  if (availableBudget < 50) {
    return prompt; // Not enough budget for meaningful context
  }

  // Extract key terms and search memory
  const terms = extractKeyTerms(prompt);
  const searchQuery = terms.join(' ');

  let memories: MemoryEntry[] = [];
  if (searchQuery.length > 0) {
    memories = await searchMemory(searchQuery, 20, cwd);
  }

  // Also get recent memories for recency
  const recent = await getRecentMemory(10, cwd);
  const seen = new Set(memories.map(m => m.id));
  for (const r of recent) {
    if (!seen.has(r.id)) {
      memories.push(r);
      seen.add(r.id);
    }
  }

  // Load lessons
  const lessons = await loadLessons(cwd);

  // Build progressive context
  const contextBlock = buildProgressiveContext(memories, lessons, availableBudget);

  if (contextBlock.length === 0) {
    return prompt;
  }

  logger.info(`[Context] Injected ${estimateTokens(contextBlock)} tokens of prior context`);

  return `${prompt}\n\n## Prior Context (auto-injected)\n${contextBlock}`;
}

// Persistent Memory Engine — cross-session memory with search, compaction, and token-awareness
import crypto from 'crypto';
import { loadMemoryStore, saveMemoryStore } from './memory-store.js';
import { estimateTokens } from './token-estimator.js';
import { isLLMAvailable, callLLM } from './llm.js';
import { logger } from './logger.js';
import type { MemoryEntry, MemoryStore } from './memory-store.js';

export type { MemoryEntry, MemoryStore } from './memory-store.js';

const MAX_TOKEN_BUDGET = 200_000;
const COMPACTION_AGE_DAYS = 7;
const DEFAULT_SEARCH_LIMIT = 20;

// Stable session ID per CLI invocation
let _sessionId: string | null = null;
function getSessionId(): string {
  if (!_sessionId) {
    _sessionId = crypto.randomUUID();
  }
  return _sessionId;
}

// Category weights for search scoring (higher = more relevant)
const CATEGORY_WEIGHTS: Record<MemoryEntry['category'], number> = {
  correction: 5,
  error: 4,
  decision: 3,
  insight: 2,
  command: 1,
};

export async function recordMemory(
  entry: Omit<MemoryEntry, 'id' | 'timestamp' | 'tokenCount' | 'sessionId'>,
  cwd?: string,
): Promise<void> {
  const store = await loadMemoryStore(cwd);
  const fullText = `${entry.summary} ${entry.detail}`;
  const tokenCount = estimateTokens(fullText);

  const memoryEntry: MemoryEntry = {
    id: crypto.randomUUID(),
    timestamp: new Date().toISOString(),
    sessionId: getSessionId(),
    tokenCount,
    ...entry,
  };

  store.entries.push(memoryEntry);
  await saveMemoryStore(store, cwd);

  // Auto-compact if over budget
  const totalTokens = store.entries.reduce((sum, e) => sum + e.tokenCount, 0);
  if (totalTokens > MAX_TOKEN_BUDGET) {
    logger.verbose('Memory token budget exceeded — triggering auto-compaction');
    await compactMemory(MAX_TOKEN_BUDGET, cwd);
  }
}

export async function searchMemory(
  query: string,
  limit = DEFAULT_SEARCH_LIMIT,
  cwd?: string,
): Promise<MemoryEntry[]> {
  const store = await loadMemoryStore(cwd);
  if (store.entries.length === 0) return [];

  const keywords = query
    .toLowerCase()
    .split(/\s+/)
    .filter(w => w.length > 2);

  if (keywords.length === 0) {
    return store.entries.slice(-limit);
  }

  const now = Date.now();

  const scored = store.entries.map(entry => {
    const searchText = `${entry.summary} ${entry.detail} ${entry.tags.join(' ')}`.toLowerCase();

    // Keyword match score
    let keywordScore = 0;
    for (const kw of keywords) {
      if (searchText.includes(kw)) keywordScore++;
    }

    // Recency bias — exponential decay over days
    const ageMs = now - new Date(entry.timestamp).getTime();
    const ageDays = ageMs / (1000 * 60 * 60 * 24);
    const recencyScore = Math.exp(-ageDays / 30); // Half-life ~21 days

    // Category weight
    const categoryScore = CATEGORY_WEIGHTS[entry.category] ?? 1;

    const totalScore = keywordScore * 3 + recencyScore * 2 + categoryScore;

    return { entry, score: totalScore, keywordScore };
  });

  // Only return entries with at least one keyword match
  return scored
    .filter(s => s.keywordScore > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map(s => s.entry);
}

export async function getRecentMemory(count = 10, cwd?: string): Promise<MemoryEntry[]> {
  const store = await loadMemoryStore(cwd);
  return store.entries.slice(-count);
}

export async function compactMemory(
  maxTokenBudget = MAX_TOKEN_BUDGET,
  cwd?: string,
  _llmCaller?: (prompt: string) => Promise<string>,
): Promise<void> {
  const store = await loadMemoryStore(cwd);
  if (store.entries.length === 0) return;

  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - COMPACTION_AGE_DAYS);
  const cutoffISO = cutoff.toISOString();

  const oldEntries = store.entries.filter(e => e.timestamp < cutoffISO);
  const recentEntries = store.entries.filter(e => e.timestamp >= cutoffISO);

  if (oldEntries.length === 0) return;

  const totalBefore = store.entries.length;

  // Try LLM-assisted compression
  const llmReady = _llmCaller != null || await isLLMAvailable();
  if (llmReady) {
    try {
      const compacted = await compactWithLLM(oldEntries, _llmCaller);
      store.entries = [...compacted, ...recentEntries];
      store.compactedAt = new Date().toISOString();
      store.totalEntriesBeforeCompaction = totalBefore;
      await saveMemoryStore(store, cwd);
      logger.verbose(`Memory compacted: ${totalBefore} -> ${store.entries.length} entries (LLM-assisted)`);
      return;
    } catch {
      logger.verbose('LLM compaction failed — falling back to truncation');
    }
  }

  // Fallback: drop detail from old entries
  const compactedOld = oldEntries.map(e => ({
    ...e,
    detail: '',
    tokenCount: estimateTokens(e.summary),
  }));

  // If still over budget, drop the oldest entries entirely
  let combined = [...compactedOld, ...recentEntries];
  let totalTokens = combined.reduce((sum, e) => sum + e.tokenCount, 0);

  while (totalTokens > maxTokenBudget && combined.length > recentEntries.length) {
    const removed = combined.shift()!;
    totalTokens -= removed.tokenCount;
  }

  store.entries = combined;
  store.compactedAt = new Date().toISOString();
  store.totalEntriesBeforeCompaction = totalBefore;
  await saveMemoryStore(store, cwd);
  logger.verbose(`Memory compacted: ${totalBefore} -> ${store.entries.length} entries (truncation)`);
}

async function compactWithLLM(
  entries: MemoryEntry[],
  _llmCaller?: (prompt: string) => Promise<string>,
): Promise<MemoryEntry[]> {
  // Group by category
  const groups = new Map<MemoryEntry['category'], MemoryEntry[]>();
  for (const entry of entries) {
    const list = groups.get(entry.category) ?? [];
    list.push(entry);
    groups.set(entry.category, list);
  }

  const compacted: MemoryEntry[] = [];

  for (const [category, groupEntries] of groups) {
    if (groupEntries.length <= 2) {
      // Keep small groups as-is
      compacted.push(...groupEntries);
      continue;
    }

    const summariesText = groupEntries
      .map((e, i) => `${i + 1}. [${e.timestamp}] ${e.summary}: ${e.detail}`)
      .join('\n');

    const prompt = `Summarize these ${groupEntries.length} ${category} memory entries into a single concise entry that preserves all key decisions, errors, and insights. Return ONLY the summary text, nothing else.\n\n${summariesText}`;

    const response = _llmCaller
      ? await _llmCaller(prompt)
      : await callLLM(prompt, undefined, { recordMemory: false });

    compacted.push({
      id: crypto.randomUUID(),
      timestamp: new Date().toISOString(),
      sessionId: 'compaction',
      category,
      summary: `[Compacted ${groupEntries.length} ${category} entries]`,
      detail: response,
      tags: [...new Set(groupEntries.flatMap(e => e.tags))],
      relatedCommands: [...new Set(groupEntries.flatMap(e => e.relatedCommands))],
      tokenCount: estimateTokens(response),
    });
  }

  return compacted;
}

export async function getMemoryBudget(cwd?: string): Promise<{
  totalTokens: number;
  entryCount: number;
  oldestEntry: string | null;
}> {
  const store = await loadMemoryStore(cwd);
  const totalTokens = store.entries.reduce((sum, e) => sum + e.tokenCount, 0);
  const oldestEntry = store.entries.length > 0 ? store.entries[0].timestamp : null;
  return { totalTokens, entryCount: store.entries.length, oldestEntry };
}

// Low-level file I/O for persistent memory — .danteforge/memory.json
import fs from 'fs/promises';
import path from 'path';

const STATE_DIR = '.danteforge';
const MEMORY_FILE = 'memory.json';

export interface MemoryEntry {
  id: string;
  timestamp: string;
  sessionId: string;
  category: 'command' | 'decision' | 'error' | 'insight' | 'correction';
  summary: string;
  detail: string;
  tags: string[];
  relatedCommands: string[];
  tokenCount: number;
}

export interface MemoryStore {
  version: '1.0.0';
  entries: MemoryEntry[];
  compactedAt?: string;
  totalEntriesBeforeCompaction?: number;
}

function resolveMemoryPath(cwd = process.cwd()): string {
  return path.join(cwd, STATE_DIR, MEMORY_FILE);
}

function createEmptyStore(): MemoryStore {
  return { version: '1.0.0', entries: [] };
}

export async function loadMemoryStore(cwd?: string): Promise<MemoryStore> {
  const filePath = resolveMemoryPath(cwd);
  try {
    const content = await fs.readFile(filePath, 'utf8');
    const parsed = JSON.parse(content) as Partial<MemoryStore>;
    return {
      version: parsed.version ?? '1.0.0',
      entries: Array.isArray(parsed.entries) ? parsed.entries : [],
      compactedAt: parsed.compactedAt,
      totalEntriesBeforeCompaction: parsed.totalEntriesBeforeCompaction,
    };
  } catch (err) {
    if (err instanceof Error && err.message.includes('ENOENT')) {
      return createEmptyStore();
    }
    // Corrupted file — start fresh
    return createEmptyStore();
  }
}

export async function saveMemoryStore(store: MemoryStore, cwd?: string): Promise<void> {
  const filePath = resolveMemoryPath(cwd);
  const dir = path.dirname(filePath);
  await fs.mkdir(dir, { recursive: true });
  await fs.writeFile(filePath, JSON.stringify(store, null, 2));
}

// Per-provider circuit breaker — prevents hammering dead providers
// State machine: CLOSED → (failures ≥ threshold) → OPEN → (after resetTimeout) → HALF_OPEN → (success) → CLOSED

export type CircuitState = 'closed' | 'open' | 'half_open';

export interface CircuitBreakerConfig {
  failureThreshold: number;       // default: 3
  resetTimeoutMs: number;         // default: 30_000
  halfOpenSuccessThreshold: number; // default: 1
}

interface CircuitEntry {
  state: CircuitState;
  failureCount: number;
  lastFailureAt: number;
  halfOpenSuccessCount: number;
}

const DEFAULT_CONFIG: CircuitBreakerConfig = {
  failureThreshold: 3,
  resetTimeoutMs: 30_000,
  halfOpenSuccessThreshold: 1,
};

const circuits = new Map<string, CircuitEntry>();

function getOrCreateEntry(provider: string): CircuitEntry {
  let entry = circuits.get(provider);
  if (!entry) {
    entry = { state: 'closed', failureCount: 0, lastFailureAt: 0, halfOpenSuccessCount: 0 };
    circuits.set(provider, entry);
  }
  return entry;
}

/** Get the current circuit state for a provider */
export function getCircuitState(provider: string): CircuitState {
  const entry = circuits.get(provider);
  return entry?.state ?? 'closed';
}

/** Check if a request should be allowed through the circuit breaker */
export function shouldAllowRequest(
  provider: string,
  config: CircuitBreakerConfig = DEFAULT_CONFIG,
  now = Date.now(),
): boolean {
  const entry = getOrCreateEntry(provider);

  switch (entry.state) {
    case 'closed':
      return true;
    case 'open': {
      // Check if enough time has passed to transition to half_open
      if (now - entry.lastFailureAt >= config.resetTimeoutMs) {
        entry.state = 'half_open';
        entry.halfOpenSuccessCount = 0;
        return true;
      }
      return false;
    }
    case 'half_open':
      return true;
  }
}

/** Record a successful request — may transition half_open → closed */
export function recordSuccess(provider: string, config: CircuitBreakerConfig = DEFAULT_CONFIG): void {
  const entry = getOrCreateEntry(provider);

  if (entry.state === 'half_open') {
    entry.halfOpenSuccessCount++;
    if (entry.halfOpenSuccessCount >= config.halfOpenSuccessThreshold) {
      entry.state = 'closed';
      entry.failureCount = 0;
      entry.halfOpenSuccessCount = 0;
    }
  } else if (entry.state === 'closed') {
    // Reset failure count on success in closed state
    entry.failureCount = 0;
  }
}

/** Record a failed request — may transition closed → open or half_open → open */
export function recordFailure(provider: string, config: CircuitBreakerConfig = DEFAULT_CONFIG): void {
  const entry = getOrCreateEntry(provider);
  entry.failureCount++;
  entry.lastFailureAt = Date.now();

  if (entry.state === 'half_open') {
    // Any failure in half_open → back to open
    entry.state = 'open';
    entry.halfOpenSuccessCount = 0;
  } else if (entry.state === 'closed' && entry.failureCount >= config.failureThreshold) {
    entry.state = 'open';
  }
}

/** Compute exponential backoff delay for a given attempt */
export function computeBackoffDelay(
  attempt: number,
  baseMs = 1000,
  maxMs = 30_000,
): number {
  const delay = baseMs * Math.pow(2, attempt);
  return Math.min(delay, maxMs);
}

/** Reset all circuit breaker state (for testing) */
export function resetAllCircuits(): void {
  circuits.clear();
}

// TTL-based in-memory state cache — reduces disk I/O for frequent loadState/saveState calls
import { loadState, saveState, type DanteState } from './state.js';

const DEFAULT_TTL_MS = 5000;

interface CacheEntry {
  state: DanteState;
  loadedAt: number;
}

const cache = new Map<string, CacheEntry>();

function resolveCacheKey(cwd?: string): string {
  return cwd ?? process.cwd();
}

/** Load state with TTL-based caching — avoids re-reading YAML within the TTL window */
export async function cachedLoadState(opts?: { cwd?: string; ttlMs?: number }): Promise<DanteState> {
  const key = resolveCacheKey(opts?.cwd);
  const ttl = opts?.ttlMs ?? DEFAULT_TTL_MS;
  const now = Date.now();

  const entry = cache.get(key);
  if (entry && (now - entry.loadedAt) < ttl) {
    return entry.state;
  }

  const state = await loadState({ cwd: opts?.cwd });
  cache.set(key, { state, loadedAt: now });
  return state;
}

/** Save state and update the cache entry */
export async function cachedSaveState(state: DanteState, opts?: { cwd?: string }): Promise<void> {
  const key = resolveCacheKey(opts?.cwd);
  await saveState(state, { cwd: opts?.cwd });
  cache.set(key, { state, loadedAt: Date.now() });
}

/** Invalidate cache for a specific cwd, or all entries if no cwd provided */
export function invalidateStateCache(cwd?: string): void {
  if (cwd) {
    cache.delete(cwd);
  } else {
    cache.clear();
  }
}

/** Return the number of cached entries (for testing) */
export function getStateCacheSize(): number {
  return cache.size;
}

// LLM configuration constants — centralized to eliminate magic numbers
export const MAX_LLM_RETRIES = 2;
export const LLM_RETRY_DELAYS_MS = [1000, 3000] as const;
export const DEFAULT_LLM_TIMEOUT_MS = 30_000;
export const DEFAULT_OLLAMA_TIMEOUT_MS = 180_000;
export const AUDIT_STATE_CACHE_TTL_MS = 5000;

// MCP Adapter — tiered support layer for Figma integration across all editors
// Builds on mcp.ts detection with tiered capabilities per host and remote MCP support.

import path from 'path';
import { detectHost, detectMCPCapabilities, type MCPHost, type MCPCapabilities } from './mcp.js';
import { loadConfig, saveConfig, type DanteConfig } from './config.js';
import { logger } from './logger.js';
import { estimateTokens } from './token-estimator.js';

/**
 * Tiered MCP support levels per host.
 * - full: bidirectional push/pull via MCP natively (Claude Code, Codex)
 * - pull-only: can read from Figma but screenshot fallback for push (Cursor, VS Code)
 * - prompt-only: generates prompts for manual copy-paste (unknown hosts)
 */
export type MCPTier = 'full' | 'pull-only' | 'prompt-only';

export interface MCPAdapterResult {
  host: MCPHost;
  tier: MCPTier;
  capabilities: MCPCapabilities;
  figmaUrl?: string;
  mcpEndpoint: string;
}

const REMOTE_MCP_ENDPOINT = 'https://mcp.figma.com/mcp';

/**
 * Resolve the MCP tier for the detected host.
 * Claude Code and Codex get full bidirectional support.
 * Cursor, VS Code, Windsurf get pull + screenshot fallback.
 * Unknown hosts get prompt-only.
 */
export function resolveTier(host: MCPHost, hasFigmaMCP: boolean): MCPTier {
  if (!hasFigmaMCP) return 'prompt-only';

  switch (host) {
    case 'claude-code':
    case 'codex':
      return 'full';
    case 'cursor':
    case 'vscode':
    case 'windsurf':
      return 'pull-only';
    default:
      return 'prompt-only';
  }
}

/**
 * Full MCP adapter initialization — detects host, capabilities, resolves tier.
 */
export async function initMCPAdapter(hostOverride?: string): Promise<MCPAdapterResult> {
  const host = detectHost(hostOverride);
  const capabilities = await detectMCPCapabilities(host);
  const tier = resolveTier(host, capabilities.hasFigmaMCP);
  const config = await loadConfig();

  return {
    host,
    tier,
    capabilities,
    figmaUrl: config.figma?.defaultFileUrl,
    mcpEndpoint: REMOTE_MCP_ENDPOINT,
  };
}

/**
 * Get the MCP add command for a specific host.
 * Uses the new remote MCP endpoint (Feb 2026) for simpler setup.
 */
export function getMCPSetupCommand(host: MCPHost, figmaToken?: string): string {
  const tokenPlaceholder = figmaToken ?? 'YOUR_FIGMA_PERSONAL_ACCESS_TOKEN';

  switch (host) {
    case 'claude-code':
      return `claude mcp add figma-mcp --url ${REMOTE_MCP_ENDPOINT} -e FIGMA_API_KEY=${tokenPlaceholder}`;
    case 'cursor':
      return `Add to .cursor/mcp.json:\n${JSON.stringify({
        mcpServers: {
          figma: { url: REMOTE_MCP_ENDPOINT, env: { FIGMA_API_KEY: tokenPlaceholder } }
        }
      }, null, 2)}`;
    case 'codex':
      return `Add to .codex/mcp.json:\n${JSON.stringify({
        mcpServers: {
          figma: { url: REMOTE_MCP_ENDPOINT, env: { FIGMA_API_KEY: tokenPlaceholder } }
        }
      }, null, 2)}`;
    case 'vscode':
    case 'windsurf':
      return `Add to .vscode/mcp.json:\n${JSON.stringify({
        mcpServers: {
          figma: { url: REMOTE_MCP_ENDPOINT, env: { FIGMA_API_KEY: tokenPlaceholder } }
        }
      }, null, 2)}`;
    default:
      return `Configure your editor's MCP settings with:\n  Server URL: ${REMOTE_MCP_ENDPOINT}\n  Environment: FIGMA_API_KEY=${tokenPlaceholder}`;
  }
}

/**
 * Test MCP connection by checking if the remote endpoint is reachable.
 * Returns true if the endpoint responds (does not require authentication).
 */
export async function testMCPConnection(
  opts?: { _fetch?: typeof globalThis.fetch } | typeof globalThis.fetch,
): Promise<{ ok: boolean; message: string }> {
  // Support both legacy positional and new options-object style
  const fetchFn = typeof opts === 'function' ? opts : opts?._fetch ?? fetch;
  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);
    const response = await fetchFn(REMOTE_MCP_ENDPOINT, {
      method: 'HEAD',
      signal: controller.signal,
    });
    clearTimeout(timeout);
    if (response.ok || response.status === 405 || response.status === 404) {
      // 405/404 means server is up but doesn't support HEAD — that's fine
      return { ok: true, message: 'Figma MCP endpoint is reachable' };
    }
    return { ok: false, message: `Figma MCP responded with status ${response.status}` };
  } catch (err) {
    return { ok: false, message: `Cannot reach Figma MCP: ${err instanceof Error ? err.message : String(err)}` };
  }
}

/**
 * Estimate tokens for a Figma-related payload and decide on mode.
 * Modes: full (all frames), summary (selected frames), screenshot-only (just screenshots).
 * Default: summary.
 */
export function selectFigmaMode(
  payloadChars: number,
  maxTokenBudget: number = 80000,
): { mode: 'full' | 'summary' | 'screenshot-only'; tokens: number; withinBudget: boolean } {
  const tokens = estimateTokens('x'.repeat(payloadChars));

  if (tokens <= maxTokenBudget * 0.5) {
    return { mode: 'full', tokens, withinBudget: true };
  }
  if (tokens <= maxTokenBudget) {
    return { mode: 'summary', tokens, withinBudget: true };
  }
  // Over budget — warn and suggest screenshot-only
  logger.warn(
    `Figma payload (~${tokens.toLocaleString()} tokens) exceeds budget ` +
    `(${maxTokenBudget.toLocaleString()} tokens). Using screenshot-only mode.`
  );
  return { mode: 'screenshot-only', tokens, withinBudget: false };
}

/**
 * Check if a project is frontend/UI-heavy by scanning for common frontend indicators.
 * Used to auto-skip UX refinement for backend-only projects.
 */
export async function isUIProject(cwd = process.cwd()): Promise<boolean> {
  const indicators = [
    'package.json', // Check for React/Vue/Svelte/Next/etc.
    'src/components',
    'src/pages',
    'src/views',
    'src/app',
    'components',
    'pages',
    'public/index.html',
    'index.html',
    'src/App.tsx',
    'src/App.jsx',
    'src/App.vue',
    'src/App.svelte',
  ];

  const fs = await import('fs/promises');

  // Check for frontend framework in package.json
  try {
    const pkg = JSON.parse(await fs.readFile(path.join(cwd, 'package.json'), 'utf8'));
    const allDeps = { ...pkg.dependencies, ...pkg.devDependencies };
    const frontendFrameworks = ['react', 'vue', 'svelte', '@angular/core', 'next', 'nuxt', 'astro', 'solid-js', 'preact'];
    if (frontendFrameworks.some(fw => fw in allDeps)) return true;
  } catch {
    // No package.json — continue checking
  }

  // Check for UI directories/files
  for (const indicator of indicators.slice(1)) { // skip package.json already checked
    try {
      await fs.access(path.join(cwd, indicator));
      return true;
    } catch {
      // Not found — continue
    }
  }

  return false;
}

/**
 * Get project characteristics for AutoForge decision-making.
 */
export async function getProjectCharacteristics(): Promise<{
  hasUI: boolean;
  hasFigma: boolean;
  hasDesign: boolean;
}> {
  return getProjectCharacteristicsFor(process.cwd());
}

export async function getProjectCharacteristicsFor(
  cwd = process.cwd(),
  _deps?: {
    isUIProject?: (dir: string) => Promise<boolean>;
    initMCPAdapter?: (hostOverride?: string) => Promise<MCPAdapterResult>;
    fsAccess?: (p: string) => Promise<void>;
  },
): Promise<{
  hasUI: boolean;
  hasFigma: boolean;
  hasDesign: boolean;
}> {
  const checkUI = _deps?.isUIProject ?? isUIProject;
  const initAdapter = _deps?.initMCPAdapter ?? initMCPAdapter;
  const checkAccess = _deps?.fsAccess ?? (async (p: string) => { const fsm = await import('fs/promises'); await fsm.access(p); });

  const hasUI = await checkUI(cwd);
  const adapter = await initAdapter();
  const hasFigma = adapter.tier !== 'prompt-only';

  let hasDesign = false;
  try {
    await checkAccess(path.join(cwd, '.danteforge', 'DESIGN.op'));
    hasDesign = true;
  } catch { /* no design file */ }

  return { hasUI, hasFigma, hasDesign };
}

/**
 * Save Figma connection info to config after successful setup.
 */
export async function saveFigmaConfig(
  figmaUrl?: string,
  tokenPath?: string,
  serverName?: string,
  _configOps?: {
    load: () => Promise<ReturnType<typeof loadConfig>>;
    save: (config: Awaited<ReturnType<typeof loadConfig>>) => Promise<void>;
  },
): Promise<void> {
  const configLoad = _configOps?.load ?? loadConfig;
  const configSave = _configOps?.save ?? saveConfig;
  const config = await configLoad();
  config.figma = {
    ...config.figma,
    ...(figmaUrl && { defaultFileUrl: figmaUrl }),
    ...(tokenPath && { designTokensPath: tokenPath }),
    ...(serverName && { mcpServerName: serverName }),
  };
  await configSave(config);
  logger.success('Figma configuration saved');
}

// MCP (Model Context Protocol) adapter — tool-agnostic host detection + Figma prompt layer
// DanteForge does NOT implement a full MCP client. It detects the host editor,
// checks for Figma MCP server config, and generates prompts the host tool can execute.
// No external dependencies — uses only Node builtins (fs, path, os).

import fs from 'fs/promises';
import path from 'path';
import os from 'os';
import { logger } from './logger.js';

export type MCPHost = 'claude-code' | 'cursor' | 'codex' | 'vscode' | 'windsurf' | 'unknown';

export interface MCPCapabilities {
  host: MCPHost;
  hasMCP: boolean;
  hasFigmaMCP: boolean;
  figmaServerName?: string;
}

/**
 * Detect which AI coding editor is running DanteForge.
 * Checks environment variables set by each host tool.
 * Falls back to 'unknown' when no host is detected.
 *
 * @param override - Explicit host via --host flag ('auto' triggers detection)
 */
export function detectHost(override?: string): MCPHost {
  if (override && override !== 'auto') {
    const valid: MCPHost[] = ['claude-code', 'cursor', 'codex', 'vscode', 'windsurf'];
    if (valid.includes(override as MCPHost)) return override as MCPHost;
    logger.warn(`Unknown host "${override}" — falling back to auto-detection`);
  }

  const env = process.env;

  // Claude Code
  if (env.CLAUDE_CODE || env.CLAUDE_SESSION_ID || env.CLAUDE_PROJECT_DIR) return 'claude-code';

  // Cursor
  if (env.CURSOR_SESSION || env.CURSOR_TRACE_ID || env.TERM_PROGRAM === 'cursor') return 'cursor';

  // Codex (OpenAI)
  if (env.CODEX_SESSION || env.CODEX || env.CODEX_ENV) return 'codex';

  // Windsurf (check before VS Code since Windsurf is VS Code-based)
  if (env.WINDSURF_SESSION || env.TERM_PROGRAM === 'windsurf') return 'windsurf';

  // VS Code (most generic — check last)
  if (env.VSCODE_PID || env.VSCODE_CWD || env.TERM_PROGRAM === 'vscode') return 'vscode';

  return 'unknown';
}

/**
 * Detect MCP capabilities by checking host-specific config files
 * for Figma MCP server entries.
 */
export async function detectMCPCapabilities(host: MCPHost): Promise<MCPCapabilities> {
  const capabilities: MCPCapabilities = { host, hasMCP: false, hasFigmaMCP: false };

  const homeDir = os.homedir();
  const cwd = process.cwd();

  // Host-specific MCP config file locations
  const configPaths: string[] = [];
  switch (host) {
    case 'claude-code':
      configPaths.push(
        path.join(cwd, '.claude', 'mcp.json'),
        path.join(homeDir, '.claude', 'mcp.json'),
      );
      break;
    case 'cursor':
      configPaths.push(
        path.join(cwd, '.cursor', 'mcp.json'),
        path.join(homeDir, '.cursor', 'mcp.json'),
      );
      break;
    case 'vscode':
    case 'windsurf':
      configPaths.push(
        path.join(cwd, '.vscode', 'settings.json'),
        path.join(cwd, '.vscode', 'mcp.json'),
      );
      break;
    case 'codex':
      configPaths.push(
        path.join(cwd, '.codex', 'mcp.json'),
      );
      break;
    default:
      // Check common locations for unknown hosts
      configPaths.push(
        path.join(cwd, '.claude', 'mcp.json'),
        path.join(cwd, '.cursor', 'mcp.json'),
        path.join(cwd, '.vscode', 'mcp.json'),
      );
  }

  for (const configPath of configPaths) {
    try {
      const content = await fs.readFile(configPath, 'utf8');
      capabilities.hasMCP = true;

      // Check for Figma MCP server entry
      const lower = content.toLowerCase();
      if (lower.includes('figma')) {
        capabilities.hasFigmaMCP = true;
        capabilities.figmaServerName = extractFigmaServerName(content);
        break;
      }
    } catch {
      // Config file not found — continue checking
    }
  }

  return capabilities;
}

/**
 * Extract the Figma MCP server name from a config file's JSON content.
 */
function extractFigmaServerName(content: string): string | undefined {
  try {
    const parsed = JSON.parse(content);
    // MCP configs typically have a "mcpServers" key with server names
    const servers = parsed.mcpServers ?? parsed['mcp.servers'] ?? parsed;
    if (typeof servers === 'object' && servers !== null) {
      for (const key of Object.keys(servers)) {
        if (key.toLowerCase().includes('figma')) {
          return key;
        }
      }
    }
  } catch {
    // JSON parse failed — fall back to regex
    const match = content.match(/"([^"]*figma[^"]*)"\s*:/i);
    if (match) return match[1];
  }
  return undefined;
}

